   280→            Self::SearchError { .. } => "Search",
   281→            Self::ConversionError { .. } => "Conversion",
   282→            Self::ValidationError { .. } => "Validation",
   283→            Self::UnsupportedFeature { .. } => "Unsupported",
   284→            Self::Generic { .. } => "Generic",
