   293→
   294→/// Specialized result type for I/O operations
   295→pub type IoResult<T> = std::result::Result<T, BidsError>;
   296→
   297→/// Specialized result type for analysis operations
   298→pub type AnalysisResult<T> = std::result::Result<T, BidsError>;
