   301→mod tests {
   302→    use super::*;
   303→    use std::path::Path;
   304→
   305→    #[test]
   306→    fn test_error_creation() {
   307→        let err = BidsError::parse_error("test.nii.gz", "invalid format");
   308→        assert!(err.is_parse_error());
   309→        assert_eq!(err.category(), "BIDS Parsing");
   310→    }
   311→
   312→    #[test]
   313→    fn test_error_categories() {
   314→        let io_err = BidsError::file_not_found(Path::new("test.txt"));
   315→        assert!(io_err.is_io_error());
   316→        assert_eq!(io_err.category(), "IO");
   317→
   318→        let compliance_err = BidsError::compliance_error("missing required field", None);
   319→        assert!(compliance_err.is_compliance_error());
   320→        assert_eq!(compliance_err.category(), "BIDS Compliance");
   321→    }
   322→
   323→    #[test]
   324→    fn test_error_display() {
   325→        let err = BidsError::parse_error("sub-01_task-rest_bold.nii.gz", "missing run entity");
   326→        let display_str = format!("{}", err);
   327→        assert!(display_str.contains("sub-01_task-rest_bold.nii.gz"));
   328→        assert!(display_str.contains("missing run entity"));
   329→    }
   330→}

