//! Error handling for BIDS operations
//!
//! This module provides comprehensive error handling for all BIDS-related operations,
//! including parsing, file I/O, validation, and analysis.

use std::io;
use std::path::PathBuf;
use std::fmt;

/// Result type for BIDS operations
pub type Result<T> = std::result::Result<T, BidsError>;

/// Comprehensive error type for BIDS operations
#[derive(Debug, thiserror::Error)]
pub enum BidsError {
    /// I/O related errors
    #[error("I/O error: {0}")]
    Io(#[from] io::Error),

    /// JSON parsing errors
    #[error("JSON parsing error: {0}")]
    Json(#[from] serde_json::Error),

    /// CSV parsing errors
    #[error("CSV parsing error: {0}")]
    Csv(#[from] csv::Error),

    /// Regular expression errors
    #[error("Regex error: {0}")]
    Regex(#[from] regex::Error),

    /// HTTP request errors (for dataset downloads)
    #[cfg(feature = "download")]
    #[error("HTTP request error: {0}")]
    Http(#[from] reqwest::Error),

    /// BIDS filename parsing errors
    #[error("Failed to parse BIDS filename '{filename}': {reason}")]
    ParseError {
        /// The filename that failed to parse
        filename: String,
        /// The reason for the parsing failure
        reason: String,
    },

    /// BIDS project validation errors
    #[error("Invalid BIDS project at '{path}': {reason}")]
    InvalidProject {
        /// The path to the invalid project
        path: PathBuf,
        /// The reason for the validation failure
        reason: String,
    },

    /// File not found errors
    #[error("File not found: {path}")]
    FileNotFound {
        /// The path to the missing file
        path: PathBuf,
    },

    /// Directory not found errors
    #[error("Directory not found: {path}")]
    DirectoryNotFound {
        /// The path to the missing directory
        path: PathBuf,
    },

    /// BIDS compliance errors
    #[error("BIDS compliance error: {message}")]
    ComplianceError {
        /// The compliance error message
        message: String,
        /// Optional file path associated with the error
        file: Option<PathBuf>,
    },

    /// Data analysis errors
    #[error("Analysis error: {message}")]
    AnalysisError {
        /// The analysis error message
        message: String,
        /// Optional context information
        context: Option<String>,
    },

    /// Mathematical computation errors
    #[error("Mathematical computation error: {message}")]
    MathError {
        /// The math error message
        message: String,
        /// Optional additional details
        details: Option<String>,
    },

    /// Configuration errors
    #[error("Configuration error: {message}")]
    ConfigError {
        /// The configuration error message
        message: String,
    },

    /// Search/query errors
    #[error("Search error: {message}")]
    SearchError {
        /// The search error message
        message: String,
        /// Optional query that caused the error
        query: Option<String>,
    },

    /// Data conversion errors
    #[error("Data conversion error: {message}")]
    ConversionError {
        /// The conversion error message
        message: String,
        /// Source type
        from: String,
        /// Target type
        to: String,
    },

    /// Generic validation errors
    #[error("Validation error: {message}")]
    ValidationError {
        /// The validation error message
        message: String,
        /// Optional field name
        field: Option<String>,
    },

    /// Unsupported feature errors
    #[error("Unsupported feature: {feature}")]
    UnsupportedFeature {
        /// The unsupported feature
        feature: String,
    },

    /// Generic errors with context
    #[error("Error: {message}")]
    Generic {
        /// The error message
        message: String,
    },
}

impl BidsError {
    /// Create a new parse error
    pub fn parse_error(filename: impl Into<String>, reason: impl Into<String>) -> Self {
        Self::ParseError {
            filename: filename.into(),
            reason: reason.into(),
        }
    }

    /// Create a new invalid project error
    pub fn invalid_project(path: impl Into<PathBuf>, reason: impl Into<String>) -> Self {
        Self::InvalidProject {
            path: path.into(),
            reason: reason.into(),
        }
    }

    /// Create a new file not found error
    pub fn file_not_found(path: impl Into<PathBuf>) -> Self {
        Self::FileNotFound {
            path: path.into(),
        }
    }

    /// Create a new directory not found error
    pub fn directory_not_found(path: impl Into<PathBuf>) -> Self {
        Self::DirectoryNotFound {
            path: path.into(),
        }
    }

    /// Create a new compliance error
    pub fn compliance_error(message: impl Into<String>, file: Option<PathBuf>) -> Self {
        Self::ComplianceError {
            message: message.into(),
            file,
        }
    }

    /// Create a new analysis error
    pub fn analysis_error(message: impl Into<String>, context: Option<String>) -> Self {
        Self::AnalysisError {
            message: message.into(),
            context,
        }
    }

    /// Create a new math error
    pub fn math_error(message: impl Into<String>, details: Option<String>) -> Self {
        Self::MathError {
            message: message.into(),
            details,
        }
    }

    /// Create a new search error
    pub fn search_error(message: impl Into<String>, query: Option<String>) -> Self {
        Self::SearchError {
            message: message.into(),
            query,
        }
    }

    /// Create a new conversion error
    pub fn conversion_error(
        message: impl Into<String>,
        from: impl Into<String>,
        to: impl Into<String>,
    ) -> Self {
        Self::ConversionError {
            message: message.into(),
            from: from.into(),
            to: to.into(),
        }
    }

    /// Create a new validation error
    pub fn validation_error(message: impl Into<String>, field: Option<String>) -> Self {
        Self::ValidationError {
            message: message.into(),
            field,
        }
    }

    /// Create a new unsupported feature error
    pub fn unsupported_feature(feature: impl Into<String>) -> Self {
        Self::UnsupportedFeature {
            feature: feature.into(),
        }
    }

    /// Create a new generic error
    pub fn generic(message: impl Into<String>) -> Self {
        Self::Generic {
            message: message.into(),
        }
    }

    /// Check if this error is related to file I/O
    pub fn is_io_error(&self) -> bool {
        matches!(
            self,
            Self::Io(_) | Self::FileNotFound { .. } | Self::DirectoryNotFound { .. }
        )
    }

    /// Check if this error is related to parsing
    pub fn is_parse_error(&self) -> bool {
        matches!(
            self,
            Self::ParseError { .. } | Self::Json(_) | Self::Csv(_) | Self::Regex(_)
        )
    }

    /// Check if this error is related to BIDS compliance
    pub fn is_compliance_error(&self) -> bool {
        matches!(
            self,
            Self::ComplianceError { .. } | Self::ValidationError { .. }
        )
    }

    /// Get the error category as a string
    pub fn category(&self) -> &'static str {
        match self {
            Self::Io(_) | Self::FileNotFound { .. } | Self::DirectoryNotFound { .. } => "IO",
            Self::Json(_) | Self::Csv(_) | Self::Regex(_) => "Parsing",
            Self::ParseError { .. } => "BIDS Parsing",
            Self::InvalidProject { .. } => "Project Validation",
            Self::ComplianceError { .. } => "BIDS Compliance",
            Self::AnalysisError { .. } => "Analysis",
            Self::MathError { .. } => "Mathematical",
            Self::ConfigError { .. } => "Configuration",
            Self::SearchError { .. } => "Search",
            Self::ConversionError { .. } => "Conversion",
            Self::ValidationError { .. } => "Validation",
            Self::UnsupportedFeature { .. } => "Unsupported",
            Self::Generic { .. } => "Generic",
            #[cfg(feature = "download")]
            Self::Http(_) => "HTTP",
        }
    }
}

/// Specialized result type for parsing operations
pub type ParseResult<T> = std::result::Result<T, BidsError>;

/// Specialized result type for I/O operations
pub type IoResult<T> = std::result::Result<T, BidsError>;

/// Specialized result type for analysis operations
pub type AnalysisResult<T> = std::result::Result<T, BidsError>;

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::Path;

    #[test]
    fn test_error_creation() {
        let err = BidsError::parse_error("test.nii.gz", "invalid format");
        assert!(err.is_parse_error());
        assert_eq!(err.category(), "BIDS Parsing");
    }

    #[test]
    fn test_error_categories() {
        let io_err = BidsError::file_not_found(Path::new("test.txt"));
        assert!(io_err.is_io_error());
        assert_eq!(io_err.category(), "IO");

        let compliance_err = BidsError::compliance_error("missing required field", None);
        assert!(compliance_err.is_compliance_error());
        assert_eq!(compliance_err.category(), "BIDS Compliance");
    }

    #[test]
    fn test_error_display() {
        let err = BidsError::parse_error("sub-01_task-rest_bold.nii.gz", "missing run entity");
        let display_str = format!("{}", err);
        assert!(display_str.contains("sub-01_task-rest_bold.nii.gz"));
        assert!(display_str.contains("missing run entity"));
    }
}

