    10→use crate::search::SearchBuilder;
    11→
    12→/// fMRIPrep derivatives handler
    13→pub struct DerivativesHandler<'a> {
    14→    /// Reference to the BIDS project
    15→    project: &'a BidsProject,
    16→    /// Path to the derivatives directory
    17→    derivatives_path: PathBuf,
    18→}
    19→
    20→impl<'a> DerivativesHandler<'a> {
    21→    /// Create a new derivatives handler
    22→    pub fn new(project: &'a BidsProject) -> Result<Self> {
    23→        let derivatives_path = project.derivatives_path.as_ref().ok_or_else(|| {
    24→            BidsError::unsupported_feature("No derivatives directory found")
    25→        })?;
    26→
    27→        Ok(Self {
    28→            project,
    29→            derivatives_path: derivatives_path.clone(),
    30→        })
