    32→
    33→    /// Find preprocessed functional scans
    34→    pub fn preproc_scans(&self) -> SearchBuilder {
    35→        self.project
    36→            .search()
    37→            .derivatives(true)
    38→            .desc("preproc")
    39→            .suffix("bold")
    40→    }
    41→
    42→    /// Find confound files
    43→    pub fn confound_files(&self) -> SearchBuilder {
    44→        self.project
    45→            .search()
    46→            .derivatives(true)
    47→            .desc("confounds")
    48→            .suffix("regressors")
    49→    }
