     2→//!
     3→//! This module provides the main [`BidsProject`] struct and related functionality
     4→//! for managing BIDS datasets.
     5→
     6→use std::collections::HashMap;
     7→use std::path::{Path, PathBuf};
     8→use std::fs;
     9→use serde::{Deserialize, Serialize};
    10→use walkdir::WalkDir;
