   310→    /// Check file naming conventions
   311→    fn check_file_naming(&self, path: &Path, file_name: &str, subject_id: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   312→        // Skip hidden files and common metadata files
   313→        if file_name.starts_with('.') || file_name == "participants.tsv" || file_name == "dataset_description.json" {
   314→            return Ok(());
   315→        }
   316→
   317→        // Check if file follows BIDS naming convention
   318→        let valid_extensions = vec![".nii", ".nii.gz", ".json", ".tsv", ".tsv.gz", ".bval", ".bvec"];
   319→        let has_valid_extension = valid_extensions.iter().any(|ext| file_name.ends_with(ext));
   320→        
   321→        if !has_valid_extension {
   322→            issues.push(ComplianceIssue {
   323→                severity: Severity::Medium,
   324→                description: format!("File has non-standard extension: {}", file_name),
   325→                file: Some(path.to_path_buf()),
   326→                rule: "file_extension".to_string(),
   327→            });
   328→        }
   329→
   330→        // Check for valid BIDS entities
