   348→    /// Check if an entity is valid
   349→    fn is_valid_entity(&self, entity: &str) -> bool {
   350→        let valid_entities = vec![
   351→            "sub", "ses", "task", "acq", "ce", "rec", "dir", "run", "mod",
   352→            "echo", "flip", "inv", "mt", "part", "proc", "hemi", "space",
   353→            "split", "recording", "chunk", "seg", "label", "desc"
   354→        ];
   355→        
   356→        if let Some(key) = entity.split('-').next() {
