    47→    include_additional: bool,
    48→}
    49→
    50→impl EventsReader {
    51→    /// Create a new events reader
    52→    pub fn new() -> Self {
    53→        Self {
    54→            delimiter: b'\t',
    55→            include_additional: true,
    56→        }
    57→    }
    58→
