    71→    /// Read events from a CSV reader
    72→    fn read_from_reader<R: std::io::Read>(&self, reader: R) -> Result<EventData> {
    73→        let mut csv_reader = ReaderBuilder::new()
    74→            .delimiter(self.delimiter)
    75→            .has_headers(true)
    76→            .from_reader(reader);
    77→
    78→        let headers = csv_reader.headers()?.clone();
    79→        
    80→        // Find required columns
    81→        let onset_col = headers.iter().position(|h| h == "onset")
    82→            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'onset' column"))?;
    83→        
    84→        let duration_col = headers.iter().position(|h| h == "duration")
    85→            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'duration' column"))?;
    86→        
    87→        let trial_type_col = headers.iter().position(|h| h == "trial_type");
    88→        
    89→        // Initialize vectors
    90→        let mut onset = Vec::new();
    91→        let mut duration = Vec::new();
    92→        let mut trial_type = Vec::new();
    93→        let mut additional_columns: HashMap<String, Vec<String>> = HashMap::new();
    94→
    95→        // Initialize additional columns
    96→        if self.include_additional {
    97→            for (i, header) in headers.iter().enumerate() {
    98→                if i != onset_col && i != duration_col && Some(i) != trial_type_col {
    99→                    additional_columns.insert(header.to_string(), Vec::new());
   100→                }
   101→            }
   102→        }
