     1→//! Confound file reading and processing
     2→//!
     3→//! This module provides functionality for reading BIDS confound files (.tsv format)
     4→//! and processing confound variables, including PCA-based dimensionality reduction.
     5→
     6→use std::collections::HashMap;
     7→use std::path::Path;
     8→use csv::ReaderBuilder;
     9→use serde::{Deserialize, Serialize};
    10→
    11→use crate::error::{BidsError, Result};
    12→use crate::file::BidsFile;
    13→use crate::io::utils;
    14→use crate::analysis::pca::{PcaProcessor, PcaResult, pca_confounds};
    15→use super::BidsReader;
    16→
    17→/// Confound data structure
    18→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    19→pub struct ConfoundsData {
    20→    /// Confound variables (variable_name -> values)
    21→    pub variables: HashMap<String, Vec<f64>>,
    22→    /// String variables (for non-numeric columns)
    23→    pub string_variables: HashMap<String, Vec<String>>,
    24→    /// Variable names in order
    25→    pub variable_names: Vec<String>,
    26→    /// Number of time points
    27→    pub n_timepoints: usize,
    28→}
    29→
    30→/// Confound file reader
    31→pub struct ConfoundsReader {
    32→    /// Column delimiter (default: tab)
    33→    delimiter: u8,
    34→    /// Include string variables
    35→    include_string_vars: bool,
    36→    /// Filter for specific confound types
    37→    confound_filter: Option<Vec<String>>,
    38→    /// Handle missing values
    39→    handle_missing: bool,
    40→    /// Missing value replacement strategy
    41→    missing_strategy: MissingStrategy,
    42→}
    43→
    44→/// Strategy for handling missing values
    45→#[derive(Debug, Clone, Copy, PartialEq)]
    46→pub enum MissingStrategy {
    47→    /// Replace with zero
    48→    Zero,
    49→    /// Replace with mean of the column
    50→    Mean,
    51→    /// Replace with median of the column
    52→    Median,
    53→    /// Remove rows with missing values
    54→    Remove,
    55→    /// Keep as NaN (will cause errors in PCA)
    56→    Keep,
    57→}
    58→
    59→impl ConfoundsReader {
    60→    /// Create a new confounds reader
    61→    pub fn new() -> Self {
    62→        Self {
    63→            delimiter: b'\t',
    64→            include_string_vars: false,
    65→            confound_filter: None,
    66→            handle_missing: true,
    67→            missing_strategy: MissingStrategy::Mean,
    68→        }
    69→    }
    70→
    71→    /// Set the column delimiter
    72→    pub fn delimiter(mut self, delimiter: u8) -> Self {
    73→        self.delimiter = delimiter;
    74→        self
    75→    }
    76→
    77→    /// Set whether to include string variables
    78→    pub fn include_string_vars(mut self, include: bool) -> Self {
    79→        self.include_string_vars = include;
    80→        self
    81→    }
    82→
    83→    /// Set confound filter (only include variables matching these patterns)
    84→    pub fn confound_filter(mut self, filter: Vec<String>) -> Self {
    85→        self.confound_filter = Some(filter);
    86→        self
    87→    }
    88→
    89→    /// Set missing value handling strategy
    90→    pub fn missing_strategy(mut self, strategy: MissingStrategy) -> Self {
    91→        self.missing_strategy = strategy;
    92→        self.handle_missing = true;
    93→        self
    94→    }
    95→
    96→    /// Filter for motion confounds only
    97→    pub fn motion_only(mut self) -> Self {
    98→        self.confound_filter = Some(vec![
    99→            "trans_x".to_string(),
   100→            "trans_y".to_string(),
   101→            "trans_z".to_string(),
   102→            "rot_x".to_string(),
   103→            "rot_y".to_string(),
   104→            "rot_z".to_string(),
   105→        ]);
   106→        self
   107→    }
   108→
   109→    /// Filter for tissue confounds only
   110→    pub fn tissue_only(mut self) -> Self {
   111→        self.confound_filter = Some(vec![
   112→            "csf".to_string(),
   113→            "white_matter".to_string(),
   114→            "global_signal".to_string(),
   115→        ]);
   116→        self
   117→    }
   118→
   119→    /// Filter for common fMRIPrep confounds
   120→    pub fn fmriprep_common(mut self) -> Self {
   121→        self.confound_filter = Some(vec![
   122→            "trans_x".to_string(),
   123→            "trans_y".to_string(),
   124→            "trans_z".to_string(),
   125→            "rot_x".to_string(),
   126→            "rot_y".to_string(),
   127→            "rot_z".to_string(),
   128→            "csf".to_string(),
   129→            "white_matter".to_string(),
   130→            "global_signal".to_string(),
   131→            "framewise_displacement".to_string(),
   132→            "dvars".to_string(),
   133→        ]);
   134→        self
   135→    }
   136→
   137→    /// Read confounds from a CSV reader
   138→    fn read_from_reader<R: std::io::Read>(&self, reader: R) -> Result<ConfoundsData> {
   139→        let mut csv_reader = ReaderBuilder::new()
   140→            .delimiter(self.delimiter)
   141→            .has_headers(true)
   142→            .from_reader(reader);
   143→
   144→        let headers = csv_reader.headers()?.clone();
   145→        let mut variables = HashMap::new();
   146→        let mut string_variables = HashMap::new();
   147→        let mut variable_names = Vec::new();
   148→
   149→        // Initialize storage for each column
   150→        for header in headers.iter() {
   151→            if let Some(ref filter) = self.confound_filter {
   152→                if !filter.iter().any(|pattern| header.to_lowercase().contains(&pattern.to_lowercase())) {
   153→                    continue;
   154→                }
   155→            }
   156→            
   157→            variables.insert(header.to_string(), Vec::new());
   158→            if self.include_string_vars {
   159→                string_variables.insert(header.to_string(), Vec::new());
   160→            }
   161→            variable_names.push(header.to_string());
   162→        }
   163→
   164→        let mut n_timepoints = 0;
   165→
   166→        // Read records
   167→        for result in csv_reader.records() {
   168→            let record = result?;
   169→            n_timepoints += 1;
   170→
   171→            for (i, header) in headers.iter().enumerate() {
   172→                if !variable_names.contains(&header.to_string()) {
   173→                    continue;
   174→                }
   175→
   176→                if let Some(value_str) = record.get(i) {
   177→                    // Try to parse as number
   178→                    if let Ok(value) = value_str.parse::<f64>() {
   179→                        if let Some(var_data) = variables.get_mut(header) {
   180→                            var_data.push(value);
   181→                        }
   182→                    } else if value_str.is_empty() || value_str.to_lowercase() == "n/a" || value_str.to_lowercase() == "nan" {
   183→                        // Handle missing values
   184→                        if let Some(var_data) = variables.get_mut(header) {
   185→                            var_data.push(f64::NAN);
   186→                        }
   187→                    } else {
   188→                        // String value
   189→                        if let Some(var_data) = variables.get_mut(header) {
   190→                            var_data.push(f64::NAN);
   191→                        }
   192→                        if self.include_string_vars {
   193→                            if let Some(str_data) = string_variables.get_mut(header) {
   194→                                str_data.push(value_str.to_string());
   195→                            }
   196→                        }
   197→                    }
   198→                }
   199→            }
   200→        }
   201→
   202→        // Handle missing values
   203→        if self.handle_missing {
   204→            for (var_name, var_data) in variables.iter_mut() {
   205→                self.handle_missing_values(var_name, var_data)?;
   206→            }
   207→        }
   208→
   209→        Ok(ConfoundsData {
   210→            variables,
   211→            string_variables,
   212→            variable_names,
   213→            n_timepoints,
   214→        })
   215→    }
   216→
   217→    /// Handle missing values in a variable
   218→    fn handle_missing_values(&self, var_name: &str, data: &mut Vec<f64>) -> Result<()> {
   219→        let nan_indices: Vec<usize> = data.iter()
   220→            .enumerate()
   221→            .filter(|(_, &value)| value.is_nan())
   222→            .map(|(i, _)| i)
   223→            .collect();
   224→
   225→        if nan_indices.is_empty() {
   226→            return Ok(());
   227→        }
   228→
   229→        match self.missing_strategy {
   230→            MissingStrategy::Zero => {
   231→                for &idx in &nan_indices {
   232→                    data[idx] = 0.0;
   233→                }
   234→            }
   235→            MissingStrategy::Mean => {
   236→                let valid_values: Vec<f64> = data.iter()
   237→                    .filter(|&&x| !x.is_nan())
   238→                    .copied()
   239→                    .collect();
   240→                
   241→                if valid_values.is_empty() {
   242→                    return Err(BidsError::parse_error(
   243→                        "confounds.tsv",
   244→                        &format!("Variable '{}' has no valid values", var_name),
   245→                    ));
   246→                }
   247→
   248→                let mean = valid_values.iter().sum::<f64>() / valid_values.len() as f64;
   249→                for &idx in &nan_indices {
   250→                    data[idx] = mean;
   251→                }
   252→            }
   253→            MissingStrategy::Median => {
   254→                let mut valid_values: Vec<f64> = data.iter()
   255→                    .filter(|&&x| !x.is_nan())
   256→                    .copied()
   257→                    .collect();
   258→                
   259→                if valid_values.is_empty() {
   260→                    return Err(BidsError::parse_error(
   261→                        "confounds.tsv",
   262→                        &format!("Variable '{}' has no valid values", var_name),
   263→                    ));
   264→                }
   265→
   266→                valid_values.sort_by(|a, b| a.partial_cmp(b).unwrap());
   267→                let median = if valid_values.len() % 2 == 0 {
   268→                    (valid_values[valid_values.len() / 2 - 1] + valid_values[valid_values.len() / 2]) / 2.0
   269→                } else {
   270→                    valid_values[valid_values.len() / 2]
   271→                };
   272→
   273→                for &idx in &nan_indices {
   274→                    data[idx] = median;
   275→                }
   276→            }
   277→            MissingStrategy::Remove => {
   278→                // This is more complex and would require removing entire rows
   279→                // For now, just replace with zero
   280→                for &idx in &nan_indices {
   281→                    data[idx] = 0.0;
   282→                }
   283→            }
   284→            MissingStrategy::Keep => {
   285→                // Do nothing - keep NaN values
   286→            }
   287→        }
   288→
   289→        Ok(())
   290→    }
   291→}
