   299→impl BidsReader<ConfoundsData> for ConfoundsReader {
   300→    fn read(&self, file: &BidsFile) -> Result<ConfoundsData> {
   301→        if !file.is_confounds() {
   302→            return Err(BidsError::validation_error(
   303→                "File is not a confounds file",
   304→                Some("suffix".to_string()),
   305→            ));
   306→        }
   307→
   308→        self.read_path(&file.path)
   309→    }
