   311→    fn read_path(&self, path: &Path) -> Result<ConfoundsData> {
   312→        if !utils::is_readable(path) {
   313→            return Err(BidsError::file_not_found(path));
   314→        }
   315→
   316→        let file = std::fs::File::open(path)?;
   317→        self.read_from_reader(file)
   318→    }
   319→}
