    64→    pub participants: Vec<Participant>,
    65→    /// Available tasks in the dataset
    66→    pub tasks: Vec<String>,
    67→    /// Whether the dataset has session-level organization
    68→    pub has_sessions: bool,
    69→    /// Whether fMRIPrep derivatives are available
    70→    pub has_derivatives: bool,
    71→    /// Path to derivatives directory (if available)
    72→    pub derivatives_path: Option<PathBuf>,
    73→    /// Dataset description metadata
    74→    pub description: HashMap<String, serde_json::Value>,
    75→}
    76→
    77→impl BidsProject {
    78→    /// Create a new BIDS project from a directory path
    79→    ///
    80→    /// # Arguments
    81→    ///
    82→    /// * `path` - Path to the BIDS dataset root directory
    83→    ///
    84→    /// # Returns
    85→    ///
    86→    /// A new `BidsProject` instance or an error if the directory is not a valid BIDS dataset
    87→    ///
    88→    /// # Examples
    89→    ///
    90→    /// ```rust
    91→    /// use bids_rust::BidsProject;
    92→    /// 
    93→    /// # fn example() -> bids_rust::Result<()> {
    94→    /// let project = BidsProject::new("/path/to/bids/dataset")?;
    95→    /// println!("Loaded project: {}", project.name);
    96→    /// # Ok(())
    97→    /// # }
    98→    /// ```
    99→    pub fn new<P: AsRef<Path>>(path: P) -> Result<Self> {
   100→        let path = path.as_ref();
   101→        let path = path.canonicalize().map_err(|e| {
   102→            BidsError::invalid_project(path, format!("Cannot access path: {}", e))
   103→        })?;
   104→
   105→        // Validate basic BIDS structure
   106→        Self::validate_bids_directory(&path)?;
   107→
   108→        let name = path
   109→            .file_name()
   110→            .and_then(|n| n.to_str())
   111→            .unwrap_or("unknown")
   112→            .to_string();
   113→
   114→        // Read dataset description
   115→        let description = Self::read_dataset_description(&path)?;
   116→
   117→        // Initialize project
   118→        let mut project = Self {
   119→            name,
   120→            path: path.clone(),
   121→            participants: Vec::new(),
   122→            tasks: Vec::new(),
   123→            has_sessions: false,
   124→            has_derivatives: false,
   125→            derivatives_path: None,
   126→            description,
   127→        };
   128→
   129→        // Load participants
   130→        project.load_participants()?;
   131→        
   132→        // Discover structure
   133→        project.discover_structure()?;
   134→
   135→        Ok(project)
   136→    }
   137→
   138→    /// Create a new BIDS project with fMRIPrep derivatives
   139→    ///
   140→    /// # Arguments
   141→    ///
   142→    /// * `path` - Path to the BIDS dataset root directory
   143→    /// * `derivatives_path` - Optional path to derivatives directory
   144→    ///
   145→    /// # Returns
   146→    ///
   147→    /// A new `BidsProject` instance with derivatives support
   148→    pub fn with_derivatives<P: AsRef<Path>>(
   149→        path: P,
   150→        derivatives_path: Option<P>,
   151→    ) -> Result<Self> {
   152→        let mut project = Self::new(path)?;
   153→        
   154→        if let Some(deriv_path) = derivatives_path {
   155→            let deriv_path = deriv_path.as_ref();
   156→            if deriv_path.exists() {
   157→                project.has_derivatives = true;
   158→                project.derivatives_path = Some(deriv_path.to_path_buf());
   159→            }
   160→        } else {
   161→            // Look for derivatives in the standard location
   162→            let deriv_path = project.path.join("derivatives");
