   235→    /// Get project summary statistics
   236→    pub fn summary(&self) -> ProjectSummary {
   237→        // Discover modalities and count files
   238→        let mut modalities = std::collections::HashSet::new();
   239→        let mut n_files = 0;
   240→        let mut total_size = 0u64;
   241→        
   242→        // Walk through the project directory to gather statistics
   243→        if let Ok(entries) = walkdir::WalkDir::new(&self.path)
   244→            .min_depth(1)
   245→            .into_iter()
   246→            .filter_map(|e| e.ok())
