   260→                    if let Some(parent) = path.parent() {
   261→                        if let Some(dir_name) = parent.file_name().and_then(|n| n.to_str()) {
   262→                            let valid_modalities = vec!["anat", "func", "dwi", "fmap", "perf", "meg", "eeg", "ieeg", "beh"];
   263→                            if valid_modalities.contains(&dir_name) {
