   254→    pub fn is_func(&self) -> bool {
   255→        self.kind.as_deref() == Some("func") || self.modality.as_deref() == Some("bold")
   256→    }
   257→
   258→    /// Check if this is an anatomical MRI file
   259→    pub fn is_anat(&self) -> bool {
   260→        self.kind.as_deref() == Some("anat")
   261→            || self.modality.as_deref().map_or(false, |m| {
   262→                matches!(m, "T1w" | "T2w" | "FLAIR" | "PDw" | "T1rho" | "T1map" | "T2map")
   263→            })
   264→    }
