    16→/// Severity level for compliance issues
    17→#[derive(Debug, Clone, PartialEq, Eq, Hash, PartialOrd, Ord)]
    18→pub enum Severity {
    19→    /// Critical issues that prevent the dataset from being BIDS-compliant
    20→    Critical,
    21→    /// High priority issues that should be addressed
    22→    High,
    23→    /// Medium priority issues
    24→    Medium,
    25→    /// Low priority issues or recommendations
    26→    Low,
    27→}
    28→
    29→/// A compliance issue found during validation
    30→#[derive(Debug, Clone)]
    31→pub struct ComplianceIssue {
    32→    /// Severity of the issue
    33→    pub severity: Severity,
    34→    /// Description of the issue
    35→    pub description: String,
    36→    /// File path associated with the issue (if applicable)
