    61→impl ComplianceChecker {
    62→    /// Create a new compliance checker
    63→    pub fn new() -> Self {
    64→        Self {
    65→            check_recommendations: true,
    66→            check_derivatives: true,
    67→        }
    68→    }
    69→
    70→    /// Set whether to check for optional recommendations
