    82→    /// Check compliance of a BIDS project
    83→    pub fn check_project(&self, project: &BidsProject) -> Result<ComplianceResult> {
    84→        let mut issues = Vec::new();
    85→        let mut files_checked = 0;
    86→
    87→        // Check required files
    88→        self.check_required_files(project, &mut issues)?;
    89→
    90→        // Check participants.tsv
    91→        self.check_participants_file(project, &mut issues)?;
    92→
    93→        // Check dataset_description.json
    94→        self.check_dataset_description(project, &mut issues)?;
    95→
    96→        // Check subject directories
    97→        self.check_subject_directories(project, &mut issues, &mut files_checked)?;
    98→
    99→        // Check if there are any critical issues
   100→        let passed = !issues.iter().any(|issue| issue.severity == Severity::Critical);
   101→
   102→        Ok(ComplianceResult {
   103→            passed,
   104→            issues,
   105→            files_checked,
   106→        })
   107→    }
   108→
   109→    /// Check for required files
   110→    fn check_required_files(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   111→        // Check participants.tsv
   112→        let participants_file = project.path.join("participants.tsv");
   113→        if !participants_file.exists() {
   114→            issues.push(ComplianceIssue {
   115→                severity: Severity::Critical,
   116→                description: "Missing required participants.tsv file".to_string(),
   117→                file: Some(participants_file),
   118→                rule: "participants.tsv".to_string(),
   119→            });
   120→        }
   121→
   122→        // Check dataset_description.json
   123→        let dataset_description = project.path.join("dataset_description.json");
   124→        if !dataset_description.exists() {
   125→            issues.push(ComplianceIssue {
   126→                severity: Severity::Critical,
   127→                description: "Missing required dataset_description.json file".to_string(),
   128→                file: Some(dataset_description),
   129→                rule: "dataset_description.json".to_string(),
   130→            });
   131→        }
   132→
   133→        Ok(())
   134→    }
   135→
   136→    /// Check participants.tsv file
   137→    fn check_participants_file(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   138→        let participants_file = project.path.join("participants.tsv");
   139→        if !participants_file.exists() {
   140→            return Ok(()); // Already checked in check_required_files
   141→        }
   142→
   143→        // Read and validate participants.tsv
   144→        let content = std::fs::read_to_string(&participants_file)?;
   145→        let lines: Vec<&str> = content.lines().collect();
   146→        
   147→        if lines.is_empty() {
   148→            issues.push(ComplianceIssue {
   149→                severity: Severity::Critical,
   150→                description: "participants.tsv is empty".to_string(),
   151→                file: Some(participants_file.clone()),
   152→                rule: "participants_empty".to_string(),
   153→            });
   154→            return Ok(());
   155→        }
   156→
   157→        // Check header
   158→        let header = lines[0];
   159→        let columns: Vec<&str> = header.split('\t').collect();
   160→        
   161→        if columns.is_empty() || columns[0] != "participant_id" {
   162→            issues.push(ComplianceIssue {
   163→                severity: Severity::Critical,
   164→                description: "participants.tsv must have 'participant_id' as first column".to_string(),
   165→                file: Some(participants_file.clone()),
   166→                rule: "participants_header".to_string(),
   167→            });
   168→        }
   169→
   170→        // Validate participant IDs
   171→        for (i, line) in lines.iter().skip(1).enumerate() {
   172→            if line.is_empty() { continue; }
   173→            
   174→            let fields: Vec<&str> = line.split('\t').collect();
   175→            if fields.is_empty() { continue; }
   176→            
   177→            let participant_id = fields[0];
   178→            if !participant_id.starts_with("sub-") {
   179→                issues.push(ComplianceIssue {
   180→                    severity: Severity::Critical,
   181→                    description: format!("Invalid participant ID '{}' on line {}: must start with 'sub-'", 
   182→                                       participant_id, i + 2),
   183→                    file: Some(participants_file.clone()),
   184→                    rule: "participant_id_format".to_string(),
   185→                });
   186→            }
   187→            
   188→            // Check if participant directory exists
   189→            let participant_dir = project.path.join(participant_id);
   190→            if !participant_dir.exists() {
   191→                issues.push(ComplianceIssue {
   192→                    severity: Severity::High,
   193→                    description: format!("Participant '{}' listed in participants.tsv but directory not found", 
   194→                                       participant_id),
   195→                    file: Some(participants_file.clone()),
   196→                    rule: "participant_directory_missing".to_string(),
   197→                });
   198→            }
   199→        }
   200→
   201→        Ok(())
   202→    }
   203→
   204→    /// Check dataset_description.json file
   205→    fn check_dataset_description(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   206→        // Check required fields in dataset description
   207→        if let Some(name) = project.description.get("Name") {
   208→            if name.as_str().map_or(true, |s| s.is_empty()) {
   209→                issues.push(ComplianceIssue {
   210→                    severity: Severity::Critical,
   211→                    description: "Dataset name is missing or empty".to_string(),
   212→                    file: Some(project.path.join("dataset_description.json")),
   213→                    rule: "dataset_description.Name".to_string(),
   214→                });
   215→            }
   216→        } else {
   217→            issues.push(ComplianceIssue {
   218→                severity: Severity::Critical,
   219→                description: "Dataset name is missing from dataset_description.json".to_string(),
   220→                file: Some(project.path.join("dataset_description.json")),
   221→                rule: "dataset_description.Name".to_string(),
   222→            });
   223→        }
   224→
   225→        // Check BIDS version
   226→        if let Some(bids_version) = project.description.get("BIDSVersion") {
   227→            if bids_version.as_str().map_or(true, |s| s.is_empty()) {
   228→                issues.push(ComplianceIssue {
   229→                    severity: Severity::High,
   230→                    description: "BIDSVersion is missing or empty".to_string(),
   231→                    file: Some(project.path.join("dataset_description.json")),
   232→                    rule: "dataset_description.BIDSVersion".to_string(),
   233→                });
   234→            }
   235→        } else {
   236→            issues.push(ComplianceIssue {
   237→                severity: Severity::High,
   238→                description: "BIDSVersion is missing from dataset_description.json".to_string(),
   239→                file: Some(project.path.join("dataset_description.json")),
   240→                rule: "dataset_description.BIDSVersion".to_string(),
   241→            });
   242→        }
   243→
   244→        Ok(())
   245→    }
   246→
   247→    /// Check subject directories
   248→    fn check_subject_directories(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>, files_checked: &mut usize) -> Result<()> {
   249→        for participant in &project.participants {
   250→            let subject_dir = project.path.join(format!("sub-{}", participant.id));
   251→            
   252→            if !subject_dir.exists() {
   253→                issues.push(ComplianceIssue {
   254→                    severity: Severity::Critical,
   255→                    description: format!("Subject directory sub-{} does not exist", participant.id),
   256→                    file: Some(subject_dir),
   257→                    rule: "subject_directory".to_string(),
   258→                });
   259→                continue;
   260→            }
   261→
   262→            // Check subject directory structure
   263→            self.check_subject_directory(&subject_dir.as_path(), &participant.id, issues, files_checked)?;
   264→        }
   265→
   266→        Ok(())
   267→    }
   268→
   269→    /// Check a single subject directory
   270→    fn check_subject_directory(&self, subject_dir: &Path, subject_id: &str, issues: &mut Vec<ComplianceIssue>, files_checked: &mut usize) -> Result<()> {
   271→        // Check directory naming convention
   272→        if !subject_dir.file_name().unwrap().to_str().unwrap().starts_with("sub-") {
   273→            issues.push(ComplianceIssue {
   274→                severity: Severity::Critical,
   275→                description: "Subject directory must start with 'sub-'".to_string(),
   276→                file: Some(subject_dir.to_path_buf()),
   277→                rule: "subject_directory_naming".to_string(),
   278→            });
   279→        }
   280→
   281→        // Walk through subject directory
   282→        for entry in WalkDir::new(subject_dir).min_depth(1).max_depth(3) {
   283→            let entry = entry?;
   284→            let path = entry.path();
   285→            
   286→            if path.is_file() {
   287→                *files_checked += 1;
   288→                
   289→                // Check file naming
   290→                if let Some(file_name) = path.file_name().and_then(|f| f.to_str()) {
   291→                    self.check_file_naming(path, file_name, subject_id, issues)?;
   292→                    
   293→                    // Check JSON sidecars have corresponding data files
   294→                    if file_name.ends_with(".json") && !file_name.contains("dataset_description") {
   295→                        self.check_json_sidecar(path, issues)?;
   296→                    }
   297→                }
   298→            } else if path.is_dir() {
   299→                // Check session/modality directory naming
   300→                if let Some(dir_name) = path.file_name().and_then(|f| f.to_str()) {
   301→                    self.check_directory_naming(path, dir_name, issues)?;
   302→                }
   303→            }
   304→        }
   305→
   306→        Ok(())
   307→    }
   308→
   309→    /// Check file naming conventions
   310→    fn check_file_naming(&self, path: &Path, file_name: &str, subject_id: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   311→        // Skip hidden files and common metadata files
   312→        if file_name.starts_with('.') || file_name == "participants.tsv" || file_name == "dataset_description.json" {
   313→            return Ok(());
   314→        }
   315→
   316→        // Check if file follows BIDS naming convention
   317→        let valid_extensions = vec![".nii", ".nii.gz", ".json", ".tsv", ".tsv.gz", ".bval", ".bvec"];
   318→        let has_valid_extension = valid_extensions.iter().any(|ext| file_name.ends_with(ext));
   319→        
   320→        if !has_valid_extension {
   321→            issues.push(ComplianceIssue {
   322→                severity: Severity::Medium,
   323→                description: format!("File has non-standard extension: {}", file_name),
   324→                file: Some(path.to_path_buf()),
   325→                rule: "file_extension".to_string(),
   326→            });
   327→        }
   328→
   329→        // Check for valid BIDS entities
   330→        if file_name.contains('_') {
   331→            let parts: Vec<&str> = file_name.split('_').collect();
   332→            for part in &parts[..parts.len()-1] { // Skip the suffix
   333→                if part.contains('-') && !self.is_valid_entity(part) {
   334→                    issues.push(ComplianceIssue {
   335→                        severity: Severity::High,
   336→                        description: format!("Invalid BIDS entity: {}", part),
   337→                        file: Some(path.to_path_buf()),
   338→                        rule: "bids_entity".to_string(),
   339→                    });
   340→                }
   341→            }
   342→        }
   343→
   344→        Ok(())
   345→    }
   346→
   347→    /// Check if an entity is valid
   348→    fn is_valid_entity(&self, entity: &str) -> bool {
   349→        let valid_entities = vec![
   350→            "sub", "ses", "task", "acq", "ce", "rec", "dir", "run", "mod",
   351→            "echo", "flip", "inv", "mt", "part", "proc", "hemi", "space",
   352→            "split", "recording", "chunk", "seg", "label", "desc"
   353→        ];
   354→        
   355→        if let Some(key) = entity.split('-').next() {
   356→            valid_entities.contains(&key)
   357→        } else {
   358→            false
   359→        }
   360→    }
   361→
   362→    /// Check directory naming conventions
   363→    fn check_directory_naming(&self, path: &Path, dir_name: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   364→        // Check session directories
   365→        if dir_name.contains("ses") && !dir_name.starts_with("ses-") {
   366→            issues.push(ComplianceIssue {
   367→                severity: Severity::Critical,
   368→                description: "Session directory must start with 'ses-'".to_string(),
   369→                file: Some(path.to_path_buf()),
   370→                rule: "session_directory_naming".to_string(),
   371→            });
   372→        }
   373→
   374→        // Check modality directories
   375→        let valid_modalities = vec!["anat", "func", "dwi", "fmap", "perf", "meg", "eeg", "ieeg", "beh"];
   376→        if !valid_modalities.contains(&dir_name) && !dir_name.starts_with("ses-") && !dir_name.starts_with("sub-") {
   377→            if self.check_recommendations {
   378→                issues.push(ComplianceIssue {
   379→                    severity: Severity::Low,
   380→                    description: format!("Non-standard modality directory: {}", dir_name),
   381→                    file: Some(path.to_path_buf()),
   382→                    rule: "modality_directory".to_string(),
   383→                });
   384→            }
   385→        }
   386→
   387→        Ok(())
   388→    }
   389→
   390→    /// Check JSON sidecar files have corresponding data files
   391→    fn check_json_sidecar(&self, json_path: &Path, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   392→        let json_name = json_path.file_stem().unwrap().to_str().unwrap();
   393→        let parent = json_path.parent().unwrap();
   394→        
   395→        // Check for corresponding .nii/.nii.gz file
   396→        let nii_path = parent.join(format!("{}.nii", json_name));
   397→        let nii_gz_path = parent.join(format!("{}.nii.gz", json_name));
   398→        
   399→        if !nii_path.exists() && !nii_gz_path.exists() {
   400→            // Check if it's a task events JSON
   401→            if !json_name.contains("events") {
   402→                issues.push(ComplianceIssue {
   403→                    severity: Severity::Medium,
   404→                    description: format!("JSON sidecar {} has no corresponding data file", json_path.display()),
   405→                    file: Some(json_path.to_path_buf()),
   406→                    rule: "orphaned_sidecar".to_string(),
   407→                });
   408→            }
   409→        }
   410→        
   411→        Ok(())
   412→    }
   413→}
