   415→impl Default for ComplianceChecker {
   416→    fn default() -> Self {
   417→        Self::new()
   418→    }
   419→}
   420→
   421→/// Quick compliance check for a BIDS project
   422→pub fn check_compliance(project: &BidsProject) -> Result<ComplianceResult> {
   423→    let checker = ComplianceChecker::new();
   424→    checker.check_project(project)
