   427→impl ComplianceResult {
   428→    /// Get a summary of issues by severity
   429→    pub fn summary(&self) -> HashMap<Severity, usize> {
   430→        let mut summary = HashMap::new();
   431→        for issue in &self.issues {
   432→            *summary.entry(issue.severity.clone()).or_insert(0) += 1;
   433→        }
   434→        summary
   435→    }
   436→    
   437→    /// Get all critical issues
   438→    pub fn critical_issues(&self) -> Vec<&ComplianceIssue> {
   439→        self.issues.iter()
   440→            .filter(|issue| issue.severity == Severity::Critical)
   441→            .collect()
   442→    }
   443→    
   444→    /// Check if there are any issues of a given severity
   445→    pub fn has_issues_of_severity(&self, severity: &Severity) -> bool {
   446→        self.issues.iter().any(|issue| &issue.severity == severity)
   447→    }
   448→}
