   450→impl std::fmt::Display for ComplianceResult {
   451→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   452→        writeln!(f, "BIDS Compliance Check Result")?;
   453→        writeln!(f, "Status: {}", if self.passed { "PASSED" } else { "FAILED" })?;
   454→        writeln!(f, "Files checked: {}", self.files_checked)?;
   455→        writeln!(f, "Total issues: {}", self.issues.len())?;
   456→        
   457→        if !self.issues.is_empty() {
   458→            writeln!(f, "\nIssues by severity:")?;
   459→            let summary = self.summary();
   460→            for (severity, count) in summary {
   461→                writeln!(f, "  {:?}: {}", severity, count)?;
   462→            }
   463→            
   464→            writeln!(f, "\nDetailed issues:")?;
   465→            for (i, issue) in self.issues.iter().enumerate() {
   466→                writeln!(f, "{}. [{:?}] {}", i + 1, issue.severity, issue.description)?;
   467→                if let Some(file) = &issue.file {
   468→                    writeln!(f, "   File: {}", file.display())?;
   469→                }
   470→                writeln!(f, "   Rule: {}", issue.rule)?;
   471→            }
   472→        }
   473→        
   474→        Ok(())
   475→    }
   476→}
