     1→//! Data analysis utilities
     2→//!
     3→//! This module provides tools for analyzing BIDS data, including
     4→//! PCA processing of confound variables.
     5→
     6→pub mod pca;
     7→
     8→use crate::error::{BidsError, Result};
     9→
    10→/// Common analysis utilities
    11→pub struct AnalysisUtils;
    12→
    13→impl AnalysisUtils {
    14→    /// Center data (subtract mean)
    15→    pub fn center_data(data: &mut [f64]) {
    16→        let mean = data.iter().sum::<f64>() / data.len() as f64;
    17→        for value in data {
    18→            *value -= mean;
    19→        }
    20→    }
    21→
    22→    /// Scale data to unit variance
    23→    pub fn scale_data(data: &mut [f64]) -> Result<()> {
    24→        let n = data.len() as f64;
    25→        let mean = data.iter().sum::<f64>() / n;
    26→        
    27→        // Calculate standard deviation
    28→        let variance = data.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / (n - 1.0);
    29→        let std_dev = variance.sqrt();
    30→        
    31→        if std_dev < f64::EPSILON {
    32→            return Err(BidsError::math_error(
    33→                "Cannot scale data with zero variance",
    34→                None,
    35→            ));
    36→        }
    37→        
    38→        for value in data {
    39→            *value = (*value - mean) / std_dev;
    40→        }
    41→        
    42→        Ok(())
    43→    }
    44→
    45→    /// Center and scale data
    46→    pub fn standardize_data(data: &mut [f64]) -> Result<()> {
    47→        Self::center_data(data);
    48→        Self::scale_data(data)
    49→    }
    50→
    51→    /// Handle missing values by replacing with median
    52→    pub fn impute_missing_values(data: &mut [Option<f64>]) -> Vec<f64> {
    53→        // Calculate median of non-missing values
    54→        let mut valid_values: Vec<f64> = data.iter().filter_map(|&x| x).collect();
    55→        valid_values.sort_by(|a, b| a.partial_cmp(b).unwrap());
    56→        
    57→        let median = if valid_values.is_empty() {
    58→            0.0
    59→        } else if valid_values.len() % 2 == 0 {
    60→            let mid = valid_values.len() / 2;
    61→            (valid_values[mid - 1] + valid_values[mid]) / 2.0
    62→        } else {
    63→            valid_values[valid_values.len() / 2]
    64→        };
    65→        
    66→        // Replace missing values with median
    67→        data.iter()
    68→            .map(|&value| value.unwrap_or(median))
    69→            .collect()
    70→    }
    71→
    72→    /// Calculate correlation matrix
    73→    pub fn correlation_matrix(data: &[Vec<f64>]) -> Result<Vec<Vec<f64>>> {
    74→        let n_vars = data.len();
    75→        if n_vars == 0 {
    76→            return Err(BidsError::analysis_error("Empty data matrix", None));
    77→        }
    78→        
    79→        let n_obs = data[0].len();
    80→        if n_obs == 0 {
    81→            return Err(BidsError::analysis_error("No observations in data", None));
    82→        }
    83→        
    84→        // Check that all variables have the same number of observations
    85→        if !data.iter().all(|var| var.len() == n_obs) {
    86→            return Err(BidsError::analysis_error(
    87→                "All variables must have the same number of observations",
    88→                None,
    89→            ));
    90→        }
    91→        
    92→        let mut corr_matrix = vec![vec![0.0; n_vars]; n_vars];
    93→        
    94→        for i in 0..n_vars {
    95→            for j in i..n_vars {
