     1→//! BIDS file representation and metadata
     2→//!
     3→//! This module provides structures for representing BIDS files and their metadata,
     4→//! including entity extraction and filename reconstruction.
     5→
     6→use std::collections::HashMap;
     7→use std::path::{Path, PathBuf};
     8→use std::fmt;
     9→use serde::{Deserialize, Serialize};
    10→
    11→use crate::error::{BidsError, Result};
    12→
    13→/// BIDS entity representation
    14→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    15→pub struct BidsEntity {
    16→    /// Entity key (e.g., "sub", "ses", "task")
    17→    pub key: String,
    18→    /// Entity value (e.g., "01", "test", "rest")
    19→    pub value: String,
    20→    /// Whether this entity is required by the BIDS specification
    21→    pub required: bool,
    22→}
    23→
    24→impl BidsEntity {
    25→    /// Create a new BIDS entity
    26→    pub fn new(key: impl Into<String>, value: impl Into<String>) -> Self {
    27→        Self {
    28→            key: key.into(),
    29→            value: value.into(),
    30→            required: false,
    31→        }
    32→    }
    33→
    34→    /// Create a new required BIDS entity
    35→    pub fn required(key: impl Into<String>, value: impl Into<String>) -> Self {
    36→        Self {
    37→            key: key.into(),
    38→            value: value.into(),
    39→            required: true,
    40→        }
    41→    }
    42→
    43→    /// Get the canonical entity name (maps "subid" to "sub", "session" to "ses", etc.)
    44→    pub fn canonical_key(&self) -> &str {
    45→        match self.key.as_str() {
    46→            "subid" => "sub",
    47→            "session" => "ses",
    48→            key => key,
    49→        }
    50→    }
    51→
    52→    /// Format as BIDS entity string (e.g., "sub-01", "task-rest")
    53→    pub fn to_bids_string(&self) -> String {
    54→        format!("{}-{}", self.canonical_key(), self.value)
    55→    }
    56→}
    57→
    58→impl fmt::Display for BidsEntity {
    59→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    60→        write!(f, "{}", self.to_bids_string())
    61→    }
    62→}
    63→
    64→/// BIDS file representation
    65→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    66→pub struct BidsFile {
    67→    /// Full path to the file
    68→    pub path: PathBuf,
    69→    /// BIDS entities extracted from the filename
    70→    pub entities: HashMap<String, String>,
    71→    /// File suffix (e.g., "bold", "events", "T1w")
    72→    pub suffix: String,
    73→    /// File extension (e.g., "nii.gz", "tsv", "json")
    74→    pub extension: String,
    75→    /// File type/kind (e.g., "func", "anat", "derivatives")
    76→    pub kind: Option<String>,
    77→    /// Modality (e.g., "bold", "T1w", "dwi")
    78→    pub modality: Option<String>,
    79→    /// Whether this is a derivative file
    80→    pub is_derivative: bool,
    81→    /// Additional metadata
    82→    pub metadata: HashMap<String, serde_json::Value>,
    83→}
    84→
    85→impl BidsFile {
    86→    /// Create a new BIDS file representation
    87→    pub fn new(path: impl Into<PathBuf>) -> Self {
    88→        let path = path.into();
    89→        Self {
    90→            path,
    91→            entities: HashMap::new(),
    92→            suffix: String::new(),
    93→            extension: String::new(),
    94→            kind: None,
    95→            modality: None,
    96→            is_derivative: false,
    97→            metadata: HashMap::new(),
    98→        }
    99→    }
   100→
   101→    /// Get the filename without directory path
   102→    pub fn filename(&self) -> Option<&str> {
   103→        self.path.file_name().and_then(|n| n.to_str())
   104→    }
   105→
   106→    /// Get the filename without extension
   107→    pub fn stem(&self) -> Option<&str> {
   108→        self.path.file_stem().and_then(|s| s.to_str())
   109→    }
   110→
   111→    /// Get entity value by key
   112→    pub fn get_entity(&self, key: &str) -> Option<&str> {
   113→        self.entities.get(key).map(|s| s.as_str())
   114→    }
   115→
   116→    /// Set entity value
   117→    pub fn set_entity(&mut self, key: impl Into<String>, value: impl Into<String>) {
   118→        self.entities.insert(key.into(), value.into());
   119→    }
   120→
   121→    /// Get subject ID (without "sub-" prefix)
   122→    pub fn subject(&self) -> Option<&str> {
   123→        self.get_entity("sub").or_else(|| self.get_entity("subid"))
   124→    }
   125→
   126→    /// Get session ID (without "ses-" prefix)
   127→    pub fn session(&self) -> Option<&str> {
   128→        self.get_entity("ses").or_else(|| self.get_entity("session"))
   129→    }
   130→
   131→    /// Get task name
   132→    pub fn task(&self) -> Option<&str> {
   133→        self.get_entity("task")
   134→    }
   135→
   136→    /// Get run number
   137→    pub fn run(&self) -> Option<&str> {
   138→        self.get_entity("run")
   139→    }
   140→
   141→    /// Get acquisition parameters
   142→    pub fn acquisition(&self) -> Option<&str> {
   143→        self.get_entity("acq")
   144→    }
   145→
   146→    /// Get contrast enhancement
   147→    pub fn contrast(&self) -> Option<&str> {
   148→        self.get_entity("ce")
   149→    }
   150→
   151→    /// Get direction
   152→    pub fn direction(&self) -> Option<&str> {
   153→        self.get_entity("dir")
   154→    }
   155→
   156→    /// Get reconstruction algorithm
   157→    pub fn reconstruction(&self) -> Option<&str> {
   158→        self.get_entity("rec")
   159→    }
   160→
   161→    /// Get echo number
   162→    pub fn echo(&self) -> Option<&str> {
   163→        self.get_entity("echo")
   164→    }
   165→
   166→    /// Get space
   167→    pub fn space(&self) -> Option<&str> {
   168→        self.get_entity("space")
   169→    }
   170→
   171→    /// Get description
   172→    pub fn description(&self) -> Option<&str> {
   173→        self.get_entity("desc")
   174→    }
   175→
   176→    /// Get all entities as a vector of BidsEntity
   177→    pub fn entities_vec(&self) -> Vec<BidsEntity> {
   178→        self.entities
   179→            .iter()
   180→            .map(|(k, v)| BidsEntity::new(k.clone(), v.clone()))
   181→            .collect()
   182→    }
   183→
   184→    /// Check if this file matches the given entity filter
   185→    pub fn matches_entity(&self, key: &str, pattern: &str) -> bool {
   186→        if let Some(value) = self.get_entity(key) {
   187→            if pattern == ".*" {
   188→                return true;
   189→            }
   190→            // Simple pattern matching - in a full implementation, this would use regex
   191→            value.contains(pattern)
   192→        } else {
   193→            false
   194→        }
   195→    }
   196→
   197→    /// Check if this file matches all given entity filters
   198→    pub fn matches_entities(&self, filters: &HashMap<String, String>) -> bool {
   199→        filters
   200→            .iter()
   201→            .all(|(key, pattern)| self.matches_entity(key, pattern))
   202→    }
   203→
   204→    /// Reconstruct BIDS filename from entities
   205→    pub fn reconstruct_filename(&self) -> String {
   206→        let mut parts = Vec::new();
   207→
   208→        // Standard BIDS entity order
   209→        let ordered_keys = [
   210→            "sub", "ses", "task", "acq", "ce", "dir", "rec", "run", "echo", "space", "desc",
   211→        ];
   212→
   213→        // Add ordered entities
   214→        for key in &ordered_keys {
   215→            if let Some(value) = self.get_entity(key) {
   216→                parts.push(format!("{}-{}", key, value));
   217→            }
   218→        }
   219→
   220→        // Add remaining entities (sorted for consistency)
   221→        let mut remaining_keys: Vec<_> = self
   222→            .entities
   223→            .keys()
   224→            .filter(|k| !ordered_keys.contains(&k.as_str()))
   225→            .collect();
   226→        remaining_keys.sort();
   227→
   228→        for key in remaining_keys {
   229→            if let Some(value) = self.entities.get(key) {
   230→                parts.push(format!("{}-{}", key, value));
   231→            }
   232→        }
   233→
   234→        // Add suffix and extension
   235→        let base_name = parts.join("_");
   236→        if !self.suffix.is_empty() {
   237→            format!("{}_{}.{}", base_name, self.suffix, self.extension)
   238→        } else {
   239→            format!("{}.{}", base_name, self.extension)
   240→        }
   241→    }
   242→
   243→    /// Add metadata
   244→    pub fn add_metadata(&mut self, key: impl Into<String>, value: serde_json::Value) {
   245→        self.metadata.insert(key.into(), value);
   246→    }
   247→
   248→    /// Get metadata value
   249→    pub fn get_metadata(&self, key: &str) -> Option<&serde_json::Value> {
   250→        self.metadata.get(key)
   251→    }
   252→
   253→    /// Check if this is a functional MRI file
   254→    pub fn is_func(&self) -> bool {
   255→        self.kind.as_deref() == Some("func") || self.modality.as_deref() == Some("bold")
   256→    }
   257→
   258→    /// Check if this is an anatomical MRI file
   259→    pub fn is_anat(&self) -> bool {
   260→        self.kind.as_deref() == Some("anat")
   261→            || self.modality.as_deref().map_or(false, |m| {
   262→                matches!(m, "T1w" | "T2w" | "FLAIR" | "PDw" | "T1rho" | "T1map" | "T2map")
   263→            })
   264→    }
   265→
   266→    /// Check if this is a derivative file
   267→    pub fn is_derivative(&self) -> bool {
   268→        self.is_derivative
   269→    }
   270→
   271→    /// Check if this is an event file
   272→    pub fn is_events(&self) -> bool {
   273→        self.suffix == "events" && self.extension == "tsv"
   274→    }
   275→
   276→    /// Check if this is a sidecar JSON file
   277→    pub fn is_sidecar(&self) -> bool {
   278→        self.extension == "json"
   279→    }
   280→
   281→    /// Check if this is a confounds file
   282→    pub fn is_confounds(&self) -> bool {
   283→        self.suffix.contains("confounds") || self.get_entity("desc").map_or(false, |d| d.contains("confounds"))
   284→    }
   285→
   286→    /// Validate BIDS compliance
   287→    pub fn validate(&self) -> Result<()> {
   288→        // Check for required subject entity
   289→        if self.subject().is_none() {
   290→            return Err(BidsError::compliance_error(
   291→                "Missing required 'sub' entity",
   292→                Some(self.path.clone()),
   293→            ));
   294→        }
   295→
   296→        // Check filename format
   297→        if let Some(filename) = self.filename() {
   298→            if !filename.chars().all(|c| c.is_ascii_alphanumeric() || "-_.".contains(c)) {
   299→                return Err(BidsError::compliance_error(
   300→                    "Filename contains invalid characters",
   301→                    Some(self.path.clone()),
   302→                ));
   303→            }
   304→        }
   305→
   306→        Ok(())
   307→    }
   308→}
   309→
   310→impl fmt::Display for BidsFile {
   311→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   312→        write!(f, "{}", self.path.display())
   313→    }
   314→}
   315→
   316→/// Builder for constructing BIDS files
   317→#[derive(Debug, Default)]
   318→pub struct BidsFileBuilder {
   319→    path: Option<PathBuf>,
   320→    entities: HashMap<String, String>,
   321→    suffix: Option<String>,
   322→    extension: Option<String>,
   323→    kind: Option<String>,
   324→    modality: Option<String>,
   325→    is_derivative: bool,
   326→    metadata: HashMap<String, serde_json::Value>,
   327→}
   328→
   329→impl BidsFileBuilder {
   330→    /// Create a new builder
   331→    pub fn new() -> Self {
   332→        Self::default()
   333→    }
   334→
   335→    /// Set the file path
   336→    pub fn path(mut self, path: impl Into<PathBuf>) -> Self {
   337→        self.path = Some(path.into());
   338→        self
   339→    }
   340→
   341→    /// Add an entity
   342→    pub fn entity(mut self, key: impl Into<String>, value: impl Into<String>) -> Self {
   343→        self.entities.insert(key.into(), value.into());
   344→        self
   345→    }
   346→
   347→    /// Set the suffix
   348→    pub fn suffix(mut self, suffix: impl Into<String>) -> Self {
   349→        self.suffix = Some(suffix.into());
   350→        self
   351→    }
   352→
   353→    /// Set the extension
   354→    pub fn extension(mut self, extension: impl Into<String>) -> Self {
   355→        self.extension = Some(extension.into());
   356→        self
   357→    }
   358→
   359→    /// Set the kind
   360→    pub fn kind(mut self, kind: impl Into<String>) -> Self {
   361→        self.kind = Some(kind.into());
   362→        self
   363→    }
   364→
   365→    /// Set the modality
   366→    pub fn modality(mut self, modality: impl Into<String>) -> Self {
   367→        self.modality = Some(modality.into());
   368→        self
   369→    }
   370→
   371→    /// Mark as derivative
   372→    pub fn derivative(mut self, is_derivative: bool) -> Self {
   373→        self.is_derivative = is_derivative;
   374→        self
   375→    }
   376→
   377→    /// Add metadata
   378→    pub fn metadata(mut self, key: impl Into<String>, value: serde_json::Value) -> Self {
   379→        self.metadata.insert(key.into(), value);
   380→        self
   381→    }
   382→
   383→    /// Build the BIDS file
   384→    pub fn build(self) -> Result<BidsFile> {
   385→        let path = self.path.ok_or_else(|| {
   386→            BidsError::validation_error("Path is required", Some("path".to_string()))
   387→        })?;
   388→
   389→        let mut file = BidsFile::new(path);
   390→        file.entities = self.entities;
   391→        file.suffix = self.suffix.unwrap_or_default();
   392→        file.extension = self.extension.unwrap_or_default();
   393→        file.kind = self.kind;
   394→        file.modality = self.modality;
   395→        file.is_derivative = self.is_derivative;
   396→        file.metadata = self.metadata;
   397→
   398→        Ok(file)
   399→    }
   400→}
   401→
   402→#[cfg(test)]
   403→mod tests {
   404→    use super::*;
   405→
   406→    #[test]
