     2→//!
     3→//! This module provides functionality for parsing BIDS filenames and extracting
     4→//! entities according to the BIDS specification.
     5→
     6→use std::collections::HashMap;
     7→use regex::Regex;
     8→use once_cell::sync::Lazy;
     9→
    10→use crate::error::{BidsError, Result};
    11→use crate::file::BidsFile;
    12→
    13→/// Result of parsing a BIDS filename
    14→#[derive(Debug, Clone, PartialEq)]
    15→pub struct ParseResult {
    16→    /// Extracted entities
    17→    pub entities: HashMap<String, String>,
    18→    /// File suffix (e.g., "bold", "events")
    19→    pub suffix: String,
    20→    /// File extension (e.g., "nii.gz", "tsv")
    21→    pub extension: String,
    22→    /// File type/kind (e.g., "func", "anat")
    23→    pub kind: Option<String>,
    24→    /// Modality (e.g., "bold", "T1w")
    25→    pub modality: Option<String>,
    26→}
    27→
    28→/// BIDS filename parser
    29→pub struct BidsParser {
    30→    /// Parser specifications
    31→    parsers: Vec<ParserSpec>,
    32→}
    33→
    34→/// Parser specification for a specific file type
    35→#[derive(Debug, Clone)]
    36→struct ParserSpec {
    37→    /// File type (e.g., "func", "anat")
    38→    kind: String,
    39→    /// Regex pattern for matching filenames
    40→    pattern: Regex,
    41→    /// Entity keys that this parser extracts
    42→    entity_keys: Vec<String>,
    43→    /// Possible suffixes for this file type
    44→    suffixes: Vec<String>,
    45→    /// Possible extensions for this file type
    46→    extensions: Vec<String>,
    47→}
    48→
    49→// Compiled regex patterns for common BIDS entities
    50→static ENTITY_PATTERNS: Lazy<HashMap<&'static str, Regex>> = Lazy::new(|| {
    51→    let mut patterns = HashMap::new();
    52→    
    53→    // Core entities
    54→    patterns.insert("sub", Regex::new(r"sub-([a-zA-Z0-9]+)").unwrap());
    55→    patterns.insert("ses", Regex::new(r"ses-([a-zA-Z0-9]+)").unwrap());
    56→    patterns.insert("task", Regex::new(r"task-([a-zA-Z0-9]+)").unwrap());
    57→    patterns.insert("run", Regex::new(r"run-([0-9]+)").unwrap());
    58→    patterns.insert("acq", Regex::new(r"acq-([a-zA-Z0-9]+)").unwrap());
    59→    patterns.insert("ce", Regex::new(r"ce-([a-zA-Z0-9]+)").unwrap());
    60→    patterns.insert("dir", Regex::new(r"dir-([a-zA-Z0-9]+)").unwrap());
    61→    patterns.insert("rec", Regex::new(r"rec-([a-zA-Z0-9]+)").unwrap());
    62→    patterns.insert("echo", Regex::new(r"echo-([0-9]+)").unwrap());
    63→    patterns.insert("space", Regex::new(r"space-([a-zA-Z0-9]+)").unwrap());
    64→    patterns.insert("desc", Regex::new(r"desc-([a-zA-Z0-9]+)").unwrap());
    65→    
    66→    patterns
    67→});
    68→
    69→impl BidsParser {
    70→    /// Create a new BIDS parser
    71→    pub fn new() -> Self {
    72→        Self {
    73→            parsers: Self::create_default_parsers(),
    74→        }
    75→    }
    76→
    77→    /// Parse a BIDS filename
    78→    pub fn parse(&self, filename: &str) -> Result<ParseResult> {
    79→        for parser in &self.parsers {
    80→            if let Some(result) = self.try_parse_with_spec(filename, parser)? {
    81→                return Ok(result);
    82→            }
    83→        }
    84→        
    85→        Err(BidsError::parse_error(
