     1→//! Principal Component Analysis (PCA) implementation
     2→//!
     3→//! This module provides PCA functionality for confound variable processing,
     4→//! matching the behavior of R's prcomp function.
     5→
     6→use nalgebra::{DMatrix, SVD};
     7→use serde::{Deserialize, Serialize};
     8→use std::collections::HashMap;
     9→
    10→use crate::error::{BidsError, Result};
    11→
    12→/// PCA processor for confound variables
    13→#[derive(Debug, Clone)]
    14→pub struct PcaProcessor {
    15→    /// Data matrix (observations x variables)
    16→    pub data: DMatrix<f64>,
    17→    /// Variable names
    18→    pub variable_names: Vec<String>,
    19→    /// Whether to center the data
    20→    pub center: bool,
    21→    /// Whether to scale the data
    22→    pub scale: bool,
    23→}
    24→
    25→/// Result of PCA computation
    26→#[derive(Debug, Clone, Serialize, Deserialize)]
    27→pub struct PcaResult {
    28→    /// Principal component scores (observations x components)
    29→    pub scores: Vec<Vec<f64>>,
    30→    /// Principal component loadings (variables x components)
    31→    pub loadings: Vec<Vec<f64>>,
    32→    /// Explained variance for each component
    33→    pub explained_variance: Vec<f64>,
    34→    /// Explained variance ratio for each component
    35→    pub explained_variance_ratio: Vec<f64>,
    36→    /// Cumulative explained variance ratio
    37→    pub cumulative_variance_ratio: Vec<f64>,
    38→    /// Standard deviations of principal components
    39→    pub standard_deviations: Vec<f64>,
    40→    /// Means of original variables (if centered)
    41→    pub means: Vec<f64>,
    42→    /// Standard deviations of original variables (if scaled)
    43→    pub scales: Vec<f64>,
    44→    /// Variable names
    45→    pub variable_names: Vec<String>,
    46→}
    47→
    48→impl PcaProcessor {
    49→    /// Create a new PCA processor
    50→    pub fn new(data: DMatrix<f64>, variable_names: Vec<String>) -> Result<Self> {
    51→        if data.ncols() != variable_names.len() {
    52→            return Err(BidsError::analysis_error(
    53→                "Number of variables must match number of variable names",
    54→                None,
    55→            ));
    56→        }
    57→
    58→        Ok(Self {
    59→            data,
    60→            variable_names,
    61→            center: true,
    62→            scale: true,
    63→        })
    64→    }
    65→
    66→    /// Create PCA processor from a vector of variable data
    67→    pub fn from_variables(variables: Vec<(String, Vec<f64>)>) -> Result<Self> {
    68→        if variables.is_empty() {
    69→            return Err(BidsError::analysis_error("No variables provided", None));
    70→        }
    71→
    72→        let n_obs = variables[0].1.len();
    73→        let n_vars = variables.len();
    74→
    75→        // Check that all variables have the same number of observations
    76→        for (name, data) in &variables {
    77→            if data.len() != n_obs {
    78→                return Err(BidsError::analysis_error(
    79→                    format!("Variable '{}' has {} observations, expected {}", name, data.len(), n_obs),
    80→                    None,
    81→                ));
    82→            }
    83→        }
    84→
    85→        // Create data matrix
    86→        let mut data_matrix = DMatrix::zeros(n_obs, n_vars);
    87→        let mut variable_names = Vec::with_capacity(n_vars);
    88→
    89→        for (j, (name, data)) in variables.into_iter().enumerate() {
    90→            variable_names.push(name);
    91→            for (i, value) in data.into_iter().enumerate() {
    92→                data_matrix[(i, j)] = value;
    93→            }
    94→        }
    95→
    96→        Self::new(data_matrix, variable_names)
    97→    }
    98→
    99→    /// Create PCA processor from a HashMap of confound variables
   100→    pub fn from_confound_map(confounds: HashMap<String, Vec<f64>>) -> Result<Self> {
   101→        let variables: Vec<(String, Vec<f64>)> = confounds.into_iter().collect();
   102→        Self::from_variables(variables)
   103→    }
   104→
   105→    /// Set whether to center the data
   106→    pub fn center(mut self, center: bool) -> Self {
   107→        self.center = center;
   108→        self
   109→    }
   110→
   111→    /// Set whether to scale the data
   112→    pub fn scale(mut self, scale: bool) -> Self {
   113→        self.scale = scale;
   114→        self
   115→    }
   116→
   117→    /// Compute PCA
   118→    pub fn compute(&self) -> Result<PcaResult> {
   119→        let mut data = self.data.clone();
   120→        let mut means = vec![0.0; self.data.ncols()];
   121→        let mut scales = vec![1.0; self.data.ncols()];
   122→
   123→        // Center the data
   124→        if self.center {
   125→            for j in 0..data.ncols() {
   126→                let col = data.column(j);
   127→                let mean = col.mean();
   128→                means[j] = mean;
   129→                
   130→                for i in 0..data.nrows() {
   131→                    data[(i, j)] -= mean;
   132→                }
   133→            }
   134→        }
   135→
   136→        // Scale the data
   137→        if self.scale {
   138→            for j in 0..data.ncols() {
   139→                let col = data.column(j);
   140→                let variance = col.map(|x| x.powi(2)).sum() / (data.nrows() - 1) as f64;
   141→                let std_dev = variance.sqrt();
   142→                
   143→                if std_dev < f64::EPSILON {
   144→                    return Err(BidsError::math_error(
   145→                        format!("Variable '{}' has zero variance", self.variable_names[j]),
   146→                        None,
   147→                    ));
   148→                }
   149→                
   150→                scales[j] = std_dev;
   151→                
   152→                for i in 0..data.nrows() {
   153→                    data[(i, j)] /= std_dev;
   154→                }
   155→            }
   156→        }
   157→
   158→        // Perform SVD
   159→        let svd = SVD::new(data.clone(), true, true);
   160→        
   161→        let u = svd.u.ok_or_else(|| {
   162→            BidsError::math_error("SVD failed to compute U matrix", None)
   163→        })?;
   164→        
   165→        let v_t = svd.v_t.ok_or_else(|| {
   166→            BidsError::math_error("SVD failed to compute V^T matrix", None)
   167→        })?;
   168→        
   169→        let singular_values = svd.singular_values;
   170→        let n_components = singular_values.len();
   171→        
   172→        // Calculate explained variance
   173→        let total_variance = singular_values.iter().map(|s| s.powi(2)).sum::<f64>();
   174→        let explained_variance: Vec<f64> = singular_values
   175→            .iter()
   176→            .map(|s| s.powi(2) / (data.nrows() - 1) as f64)
   177→            .collect();
   178→        
   179→        let explained_variance_ratio: Vec<f64> = explained_variance
   180→            .iter()
   181→            .map(|var| var / total_variance * (data.nrows() - 1) as f64)
   182→            .collect();
   183→        
   184→        let cumulative_variance_ratio: Vec<f64> = explained_variance_ratio
   185→            .iter()
   186→            .scan(0.0, |acc, &x| {
   187→                *acc += x;
   188→                Some(*acc)
   189→            })
   190→            .collect();
   191→        
   192→        // Calculate standard deviations
   193→        let standard_deviations: Vec<f64> = explained_variance
   194→            .iter()
   195→            .map(|var| var.sqrt())
   196→            .collect();
   197→        
   198→        // Extract scores (principal components)
   199→        let scores_matrix = &u * DMatrix::from_diagonal(&singular_values);
   200→        let scores: Vec<Vec<f64>> = (0..scores_matrix.nrows())
   201→            .map(|i| scores_matrix.row(i).iter().cloned().collect())
   202→            .collect();
   203→        
   204→        // Extract loadings (eigenvectors)
   205→        let loadings: Vec<Vec<f64>> = (0..v_t.ncols())
   206→            .map(|j| v_t.column(j).iter().cloned().collect())
   207→            .collect();
   208→        
   209→        Ok(PcaResult {
   210→            scores,
   211→            loadings,
   212→            explained_variance,
   213→            explained_variance_ratio,
   214→            cumulative_variance_ratio,
   215→            standard_deviations,
   216→            means,
   217→            scales,
   218→            variable_names: self.variable_names.clone(),
   219→        })
   220→    }
   221→
   222→    /// Compute PCA with specified number of components
   223→    pub fn compute_n_components(&self, n_components: usize) -> Result<PcaResult> {
   224→        let mut result = self.compute()?;
   225→        
   226→        if n_components < result.scores[0].len() {
   227→            // Truncate to requested number of components
   228→            for scores_row in &mut result.scores {
   229→                scores_row.truncate(n_components);
   230→            }
   231→            
   232→            for loadings_row in &mut result.loadings {
   233→                loadings_row.truncate(n_components);
   234→            }
   235→            
   236→            result.explained_variance.truncate(n_components);
   237→            result.explained_variance_ratio.truncate(n_components);
   238→            result.cumulative_variance_ratio.truncate(n_components);
   239→            result.standard_deviations.truncate(n_components);
   240→        }
   241→        
   242→        Ok(result)
   243→    }
   244→
   245→    /// Compute PCA retaining components that explain at least the specified variance
   246→    pub fn compute_variance_threshold(&self, variance_threshold: f64) -> Result<PcaResult> {
   247→        let result = self.compute()?;
   248→        
   249→        // Find number of components needed to explain the variance
   250→        let n_components = result
   251→            .cumulative_variance_ratio
   252→            .iter()
   253→            .position(|&ratio| ratio >= variance_threshold)
   254→            .unwrap_or(result.cumulative_variance_ratio.len())
   255→            + 1;
   256→        
   257→        self.compute_n_components(n_components.min(result.explained_variance.len()))
   258→    }
   259→    
   260→    /// Compute PCA with memory optimization for large datasets
   261→    /// Uses truncated computation for datasets with many variables
   262→    pub fn compute_optimized(&self) -> Result<PcaResult> {
   263→        // For small datasets, use regular computation
   264→        if self.data.ncols() <= 1000 && self.data.nrows() <= 10000 {
   265→            return self.compute();
   266→        }
   267→        
   268→        // For large datasets, compute only top components
   269→        let n_components = if self.data.ncols() > 1000 {
   270→            (self.data.ncols() / 10).max(50).min(200)
   271→        } else {
   272→            // If many observations but few variables, still limit components
   273→            self.data.ncols().min(100)
   274→        };
   275→        
   276→        self.compute_n_components(n_components)
   277→    }
   278→    
   279→    /// Check if the dataset is large enough to benefit from optimization
   280→    pub fn should_optimize(&self) -> bool {
   281→        self.data.ncols() > 1000 || self.data.nrows() > 10000
   282→    }
   283→}
   284→
   285→impl PcaResult {
   286→    /// Get the number of components
   287→    pub fn n_components(&self) -> usize {
   288→        self.explained_variance.len()
   289→    }
   290→
   291→    /// Get the number of observations
   292→    pub fn n_observations(&self) -> usize {
   293→        self.scores.len()
   294→    }
   295→
   296→    /// Get the number of variables
   297→    pub fn n_variables(&self) -> usize {
   298→        self.variable_names.len()
   299→    }
   300→
   301→    /// Get scores as a matrix
   302→    pub fn scores_matrix(&self) -> DMatrix<f64> {
   303→        let n_obs = self.n_observations();
   304→        let n_comp = self.n_components();
   305→        
   306→        let mut matrix = DMatrix::zeros(n_obs, n_comp);
   307→        for (i, row) in self.scores.iter().enumerate() {
   308→            for (j, &value) in row.iter().enumerate() {
   309→                matrix[(i, j)] = value;
   310→            }
   311→        }
   312→        matrix
   313→    }
   314→
   315→    /// Get loadings as a matrix
   316→    pub fn loadings_matrix(&self) -> DMatrix<f64> {
   317→        let n_vars = self.n_variables();
   318→        let n_comp = self.n_components();
   319→        
   320→        let mut matrix = DMatrix::zeros(n_vars, n_comp);
   321→        for (i, row) in self.loadings.iter().enumerate() {
   322→            for (j, &value) in row.iter().enumerate() {
   323→                matrix[(i, j)] = value;
   324→            }
   325→        }
   326→        matrix
   327→    }
   328→
   329→    /// Get component names
   330→    pub fn component_names(&self) -> Vec<String> {
   331→        (1..=self.n_components())
   332→            .map(|i| format!("PC{}", i))
   333→            .collect()
   334→    }
   335→
   336→    /// Get summary statistics
   337→    pub fn summary(&self) -> PcaSummary {
   338→        PcaSummary {
   339→            n_components: self.n_components(),
   340→            n_observations: self.n_observations(),
   341→            n_variables: self.n_variables(),
   342→            total_variance_explained: self.cumulative_variance_ratio.last().copied().unwrap_or(0.0),
   343→            component_names: self.component_names(),
   344→            explained_variance_ratio: self.explained_variance_ratio.clone(),
   345→        }
   346→    }
   347→}
   348→
   349→/// Summary statistics for PCA results
   350→#[derive(Debug, Clone, Serialize, Deserialize)]
   351→pub struct PcaSummary {
   352→    /// Number of components
   353→    pub n_components: usize,
   354→    /// Number of observations
   355→    pub n_observations: usize,
   356→    /// Number of variables
   357→    pub n_variables: usize,
   358→    /// Total variance explained
   359→    pub total_variance_explained: f64,
   360→    /// Component names
   361→    pub component_names: Vec<String>,
   362→    /// Explained variance ratio for each component
   363→    pub explained_variance_ratio: Vec<f64>,
   364→}
   365→
   366→impl std::fmt::Display for PcaSummary {
   367→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   368→        writeln!(f, "PCA Summary")?;
   369→        writeln!(f, "Components: {}", self.n_components)?;
   370→        writeln!(f, "Observations: {}", self.n_observations)?;
   371→        writeln!(f, "Variables: {}", self.n_variables)?;
   372→        writeln!(f, "Total Variance Explained: {:.2}%", self.total_variance_explained * 100.0)?;
   373→        writeln!(f, "\nVariance Explained by Component:")?;
   374→        
   375→        for (i, &ratio) in self.explained_variance_ratio.iter().enumerate() {
   376→            writeln!(f, "  PC{}: {:.2}%", i + 1, ratio * 100.0)?;
   377→        }
   378→        
   379→        Ok(())
   380→    }
   381→}
   382→
   383→/// Convenience function to perform PCA on confound variables
   384→pub fn pca_confounds(
   385→    confounds: HashMap<String, Vec<f64>>,
   386→    n_components: Option<usize>,
   387→    variance_threshold: Option<f64>,
   388→) -> Result<PcaResult> {
   389→    let processor = PcaProcessor::from_confound_map(confounds)?;
   390→    
   391→    match (n_components, variance_threshold) {
   392→        (Some(n), None) => processor.compute_n_components(n),
   393→        (None, Some(threshold)) => processor.compute_variance_threshold(threshold),
   394→        (Some(n), Some(threshold)) => {
   395→            let result = processor.compute_variance_threshold(threshold)?;
   396→            if result.n_components() > n {
   397→                processor.compute_n_components(n)
   398→            } else {
   399→                Ok(result)
   400→            }
   401→        }
   402→        (None, None) => processor.compute(),
   403→    }
   404→}
