     1→//! BIDS project management
     2→//!
     3→//! This module provides the main [`BidsProject`] struct and related functionality
     4→//! for managing BIDS datasets.
     5→
     6→use std::collections::HashMap;
     7→use std::path::{Path, PathBuf};
     8→use std::fs;
     9→use serde::{Deserialize, Serialize};
    10→use walkdir::WalkDir;
    11→
    12→use crate::error::{BidsError, Result};
    13→use crate::file::BidsFile;
    14→use crate::search::SearchBuilder;
    15→
    16→/// Represents a participant in a BIDS dataset
    17→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    18→pub struct Participant {
    19→    /// Participant identifier (without "sub-" prefix)
    20→    pub id: String,
    21→    /// Sessions associated with this participant
    22→    pub sessions: Vec<String>,
    23→    /// Additional metadata from participants.tsv
    24→    pub metadata: HashMap<String, String>,
    25→}
    26→
    27→impl Participant {
    28→    /// Create a new participant
    29→    pub fn new(id: impl Into<String>) -> Self {
    30→        Self {
    31→            id: id.into(),
    32→            sessions: Vec::new(),
    33→            metadata: HashMap::new(),
    34→        }
    35→    }
    36→
    37→    /// Add a session to this participant
    38→    pub fn add_session(&mut self, session: impl Into<String>) {
    39→        let session = session.into();
    40→        if !self.sessions.contains(&session) {
    41→            self.sessions.push(session);
    42→        }
    43→    }
    44→
    45→    /// Add metadata for this participant
    46→    pub fn add_metadata(&mut self, key: impl Into<String>, value: impl Into<String>) {
    47→        self.metadata.insert(key.into(), value.into());
    48→    }
    49→
    50→    /// Get metadata value by key
    51→    pub fn get_metadata(&self, key: &str) -> Option<&str> {
    52→        self.metadata.get(key).map(|s| s.as_str())
    53→    }
    54→}
    55→
    56→/// Main BIDS project representation
    57→#[derive(Debug, Clone)]
    58→pub struct BidsProject {
    59→    /// Project name (typically the dataset directory name)
    60→    pub name: String,
    61→    /// Path to the root of the BIDS dataset
    62→    pub path: PathBuf,
    63→    /// List of participants in the dataset
    64→    pub participants: Vec<Participant>,
    65→    /// Available tasks in the dataset
    66→    pub tasks: Vec<String>,
    67→    /// Whether the dataset has session-level organization
    68→    pub has_sessions: bool,
    69→    /// Whether fMRIPrep derivatives are available
    70→    pub has_derivatives: bool,
    71→    /// Path to derivatives directory (if available)
    72→    pub derivatives_path: Option<PathBuf>,
    73→    /// Dataset description metadata
    74→    pub description: HashMap<String, serde_json::Value>,
    75→}
    76→
    77→impl BidsProject {
    78→    /// Create a new BIDS project from a directory path
    79→    ///
    80→    /// # Arguments
    81→    ///
    82→    /// * `path` - Path to the BIDS dataset root directory
    83→    ///
    84→    /// # Returns
    85→    ///
    86→    /// A new `BidsProject` instance or an error if the directory is not a valid BIDS dataset
    87→    ///
    88→    /// # Examples
    89→    ///
    90→    /// ```rust
    91→    /// use bids_rust::BidsProject;
    92→    /// 
    93→    /// # fn example() -> bids_rust::Result<()> {
    94→    /// let project = BidsProject::new("/path/to/bids/dataset")?;
    95→    /// println!("Loaded project: {}", project.name);
    96→    /// # Ok(())
    97→    /// # }
    98→    /// ```
    99→    pub fn new<P: AsRef<Path>>(path: P) -> Result<Self> {
   100→        let path = path.as_ref();
   101→        let path = path.canonicalize().map_err(|e| {
   102→            BidsError::invalid_project(path, format!("Cannot access path: {}", e))
   103→        })?;
   104→
   105→        // Validate basic BIDS structure
   106→        Self::validate_bids_directory(&path)?;
   107→
   108→        let name = path
   109→            .file_name()
   110→            .and_then(|n| n.to_str())
   111→            .unwrap_or("unknown")
   112→            .to_string();
   113→
   114→        // Read dataset description
   115→        let description = Self::read_dataset_description(&path)?;
   116→
   117→        // Initialize project
   118→        let mut project = Self {
   119→            name,
   120→            path: path.clone(),
   121→            participants: Vec::new(),
   122→            tasks: Vec::new(),
   123→            has_sessions: false,
   124→            has_derivatives: false,
   125→            derivatives_path: None,
   126→            description,
   127→        };
   128→
   129→        // Load participants
   130→        project.load_participants()?;
   131→        
   132→        // Discover structure
   133→        project.discover_structure()?;
   134→
   135→        Ok(project)
   136→    }
   137→
   138→    /// Create a new BIDS project with fMRIPrep derivatives
   139→    ///
   140→    /// # Arguments
   141→    ///
   142→    /// * `path` - Path to the BIDS dataset root directory
   143→    /// * `derivatives_path` - Optional path to derivatives directory
   144→    ///
   145→    /// # Returns
   146→    ///
   147→    /// A new `BidsProject` instance with derivatives support
   148→    pub fn with_derivatives<P: AsRef<Path>>(
   149→        path: P,
   150→        derivatives_path: Option<P>,
   151→    ) -> Result<Self> {
   152→        let mut project = Self::new(path)?;
   153→        
   154→        if let Some(deriv_path) = derivatives_path {
   155→            let deriv_path = deriv_path.as_ref();
   156→            if deriv_path.exists() {
   157→                project.has_derivatives = true;
   158→                project.derivatives_path = Some(deriv_path.to_path_buf());
   159→            }
   160→        } else {
   161→            // Look for derivatives in the standard location
   162→            let deriv_path = project.path.join("derivatives");
   163→            if deriv_path.exists() {
   164→                project.has_derivatives = true;
   165→                project.derivatives_path = Some(deriv_path);
   166→            }
