     1→//! Event file reading and processing
     2→//!
     3→//! This module provides functionality for reading BIDS event files (.tsv format)
     4→//! and processing trial-by-trial experimental data.
     5→
     6→use std::collections::HashMap;
     7→use std::path::Path;
     8→use csv::ReaderBuilder;
     9→use serde::{Deserialize, Serialize};
    10→
    11→use crate::error::{BidsError, Result};
    12→use crate::file::BidsFile;
    13→use crate::io::utils;
    14→use super::BidsReader;
    15→
    16→/// Event data structure
    17→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    18→pub struct EventData {
    19→    /// Event onset times (in seconds)
    20→    pub onset: Vec<f64>,
    21→    /// Event durations (in seconds)
    22→    pub duration: Vec<f64>,
    23→    /// Trial types or event labels
    24→    pub trial_type: Vec<String>,
    25→    /// Additional event columns
    26→    pub additional_columns: HashMap<String, Vec<String>>,
    27→}
    28→
    29→/// Individual event record
    30→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    31→pub struct EventRecord {
    32→    /// Event onset time (in seconds)
    33→    pub onset: f64,
    34→    /// Event duration (in seconds)
    35→    pub duration: f64,
    36→    /// Trial type or event label
    37→    pub trial_type: String,
    38→    /// Additional event data
    39→    pub additional_data: HashMap<String, String>,
    40→}
    41→
    42→/// Event file reader
    43→pub struct EventsReader {
    44→    /// Column delimiter (default: tab)
    45→    delimiter: u8,
    46→    /// Whether to include additional columns
    47→    include_additional: bool,
    48→}
    49→
    50→impl EventsReader {
    51→    /// Create a new events reader
    52→    pub fn new() -> Self {
    53→        Self {
    54→            delimiter: b'\t',
    55→            include_additional: true,
    56→        }
    57→    }
    58→
    59→    /// Set the column delimiter
    60→    pub fn delimiter(mut self, delimiter: u8) -> Self {
    61→        self.delimiter = delimiter;
    62→        self
    63→    }
    64→
    65→    /// Set whether to include additional columns
    66→    pub fn include_additional(mut self, include: bool) -> Self {
    67→        self.include_additional = include;
    68→        self
    69→    }
    70→
    71→    /// Read events from a CSV reader
    72→    fn read_from_reader<R: std::io::Read>(&self, reader: R) -> Result<EventData> {
    73→        let mut csv_reader = ReaderBuilder::new()
    74→            .delimiter(self.delimiter)
    75→            .has_headers(true)
    76→            .from_reader(reader);
    77→
    78→        let headers = csv_reader.headers()?.clone();
    79→        
    80→        // Find required columns
    81→        let onset_col = headers.iter().position(|h| h == "onset")
    82→            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'onset' column"))?;
    83→        
    84→        let duration_col = headers.iter().position(|h| h == "duration")
    85→            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'duration' column"))?;
    86→        
    87→        let trial_type_col = headers.iter().position(|h| h == "trial_type");
    88→        
    89→        // Initialize vectors
    90→        let mut onset = Vec::new();
    91→        let mut duration = Vec::new();
    92→        let mut trial_type = Vec::new();
    93→        let mut additional_columns: HashMap<String, Vec<String>> = HashMap::new();
    94→
    95→        // Initialize additional columns
    96→        if self.include_additional {
    97→            for (i, header) in headers.iter().enumerate() {
    98→                if i != onset_col && i != duration_col && Some(i) != trial_type_col {
    99→                    additional_columns.insert(header.to_string(), Vec::new());
   100→                }
   101→            }
   102→        }
   103→
   104→        // Read records
   105→        for result in csv_reader.records() {
   106→            let record = result?;
   107→            
   108→            // Parse onset
   109→            let onset_str = record.get(onset_col)
   110→                .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing onset value"))?;
   111→            let onset_val = onset_str.parse::<f64>()
   112→                .map_err(|_| BidsError::parse_error("events.tsv", "Invalid onset value"))?;
   113→            onset.push(onset_val);
   114→            
   115→            // Parse duration
   116→            let duration_str = record.get(duration_col)
   117→                .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing duration value"))?;
   118→            let duration_val = duration_str.parse::<f64>()
   119→                .map_err(|_| BidsError::parse_error("events.tsv", "Invalid duration value"))?;
   120→            duration.push(duration_val);
   121→            
   122→            // Parse trial_type
   123→            let trial_type_val = if let Some(col) = trial_type_col {
   124→                record.get(col)
   125→                    .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing trial_type value"))?
   126→                    .to_string()
   127→            } else {
   128→                "n/a".to_string()
   129→            };
   130→            trial_type.push(trial_type_val);
   131→            
   132→            // Parse additional columns
   133→            if self.include_additional {
   134→                for (i, value) in record.iter().enumerate() {
   135→                    if i != onset_col && i != duration_col && Some(i) != trial_type_col {
   136→                        let header = &headers[i];
   137→                        if let Some(col_vec) = additional_columns.get_mut(header) {
   138→                            col_vec.push(value.to_string());
   139→                        }
   140→                    }
   141→                }
   142→            }
   143→        }
   144→
   145→        Ok(EventData {
   146→            onset,
   147→            duration,
   148→            trial_type,
   149→            additional_columns,
   150→        })
   151→    }
   152→
   153→    /// Convert EventData to individual records
   154→    pub fn to_records(&self, data: &EventData) -> Vec<EventRecord> {
   155→        let mut records = Vec::new();
   156→        
   157→        for i in 0..data.onset.len() {
   158→            let mut additional_data = HashMap::new();
   159→            
   160→            // Collect additional data for this record
   161→            for (col_name, col_values) in &data.additional_columns {
   162→                if let Some(value) = col_values.get(i) {
   163→                    additional_data.insert(col_name.clone(), value.clone());
   164→                }
   165→            }
   166→            
   167→            records.push(EventRecord {
   168→                onset: data.onset[i],
   169→                duration: data.duration[i],
   170→                trial_type: data.trial_type[i].clone(),
   171→                additional_data,
   172→            });
   173→        }
   174→        
   175→        records
   176→    }
   177→}
   178→
   179→impl Default for EventsReader {
   180→    fn default() -> Self {
   181→        Self::new()
   182→    }
   183→}
   184→
   185→impl BidsReader<EventData> for EventsReader {
   186→    fn read(&self, file: &BidsFile) -> Result<EventData> {
   187→        if !file.is_events() {
   188→            return Err(BidsError::validation_error(
   189→                "File is not an events file",
   190→                Some("suffix".to_string()),
   191→            ));
   192→        }
   193→        
   194→        self.read_path(&file.path)
   195→    }
   196→
   197→    fn read_path(&self, path: &Path) -> Result<EventData> {
   198→        if !utils::is_readable(path) {
   199→            return Err(BidsError::file_not_found(path));
   200→        }
   201→        
   202→        let file = std::fs::File::open(path)?;
   203→        self.read_from_reader(file)
   204→    }
   205→}
   206→
   207→impl EventData {
   208→    /// Create a new empty EventData
   209→    pub fn new() -> Self {
   210→        Self {
   211→            onset: Vec::new(),
   212→            duration: Vec::new(),
   213→            trial_type: Vec::new(),
   214→            additional_columns: HashMap::new(),
   215→        }
   216→    }
   217→
   218→    /// Get the number of events
   219→    pub fn len(&self) -> usize {
   220→        self.onset.len()
   221→    }
   222→
   223→    /// Check if the event data is empty
   224→    pub fn is_empty(&self) -> bool {
   225→        self.onset.is_empty()
   226→    }
   227→
   228→    /// Get unique trial types
   229→    pub fn unique_trial_types(&self) -> Vec<String> {
   230→        let mut types: Vec<String> = self.trial_type.iter().cloned().collect();
   231→        types.sort();
   232→        types.dedup();
   233→        types
   234→    }
   235→
   236→    /// Filter events by trial type
   237→    pub fn filter_by_trial_type(&self, trial_type: &str) -> Self {
   238→        let mut filtered = EventData::new();
   239→        
   240→        for (i, t_type) in self.trial_type.iter().enumerate() {
   241→            if t_type == trial_type {
   242→                filtered.onset.push(self.onset[i]);
   243→                filtered.duration.push(self.duration[i]);
   244→                filtered.trial_type.push(t_type.clone());
   245→                
   246→                // Copy additional columns
   247→                for (col_name, col_values) in &self.additional_columns {
   248→                    if let Some(value) = col_values.get(i) {
   249→                        filtered.additional_columns
   250→                            .entry(col_name.clone())
   251→                            .or_insert_with(Vec::new)
   252→                            .push(value.clone());
   253→                    }
   254→                }
   255→            }
   256→        }
   257→        
   258→        filtered
   259→    }
   260→
   261→    /// Get events within a time range
   262→    pub fn filter_by_time_range(&self, start: f64, end: f64) -> Self {
   263→        let mut filtered = EventData::new();
   264→        
   265→        for (i, &onset) in self.onset.iter().enumerate() {
   266→            if onset >= start && onset <= end {
   267→                filtered.onset.push(onset);
   268→                filtered.duration.push(self.duration[i]);
   269→                filtered.trial_type.push(self.trial_type[i].clone());
   270→                
   271→                // Copy additional columns
   272→                for (col_name, col_values) in &self.additional_columns {
   273→                    if let Some(value) = col_values.get(i) {
   274→                        filtered.additional_columns
   275→                            .entry(col_name.clone())
   276→                            .or_insert_with(Vec::new)
   277→                            .push(value.clone());
   278→                    }
   279→                }
   280→            }
   281→        }
   282→        
   283→        filtered
   284→    }
   285→
   286→    /// Get summary statistics
   287→    pub fn summary(&self) -> EventSummary {
   288→        let n_events = self.len();
   289→        let unique_types = self.unique_trial_types();
   290→        
   291→        let total_duration = self.duration.iter().sum();
