    16→#[derive(Debug, Clone, PartialEq, Eq, Hash, PartialOrd, Ord)]
    17→pub enum Severity {
    18→    /// Critical issues that prevent the dataset from being BIDS-compliant
    19→    Critical,
    20→    /// High priority issues that should be addressed
    21→    High,
    22→    /// Medium priority issues
    23→    Medium,
    24→    /// Low priority issues or recommendations
    25→    Low,
    26→}
    27→
    28→/// A compliance issue found during validation
    29→#[derive(Debug, Clone)]
    30→pub struct ComplianceIssue {
    31→    /// Severity of the issue
    32→    pub severity: Severity,
    33→    /// Description of the issue
    34→    pub description: String,
    35→    /// File path associated with the issue (if applicable)
    36→    pub file: Option<PathBuf>,
    37→    /// Rule that was violated
    38→    pub rule: String,
    39→}
    40→
    41→/// Result of a compliance check
    42→#[derive(Debug, Clone)]
    43→pub struct ComplianceResult {
    44→    /// Whether the dataset passed all critical checks
    45→    pub passed: bool,
    46→    /// List of issues found
    47→    pub issues: Vec<ComplianceIssue>,
    48→    /// Number of files checked
    49→    pub files_checked: usize,
    50→}
    51→
    52→/// BIDS compliance checker
    53→pub struct ComplianceChecker {
    54→    /// Whether to check for optional recommendations
    55→    check_recommendations: bool,
    56→    /// Whether to check derivatives
    57→    check_derivatives: bool,
    58→}
    59→
    60→impl ComplianceChecker {
    61→    /// Create a new compliance checker
    62→    pub fn new() -> Self {
    63→        Self {
    64→            check_recommendations: true,
    65→            check_derivatives: true,
    66→        }
    67→    }
    68→
    69→    /// Set whether to check for optional recommendations
    70→    pub fn check_recommendations(mut self, check: bool) -> Self {
    71→        self.check_recommendations = check;
    72→        self
    73→    }
    74→
    75→    /// Set whether to check derivatives
    76→    pub fn check_derivatives(mut self, check: bool) -> Self {
    77→        self.check_derivatives = check;
    78→        self
    79→    }
    80→
    81→    /// Check compliance of a BIDS project
    82→    pub fn check_project(&self, project: &BidsProject) -> Result<ComplianceResult> {
    83→        let mut issues = Vec::new();
    84→        let mut files_checked = 0;
    85→
    86→        // Check required files
    87→        self.check_required_files(project, &mut issues)?;
    88→
    89→        // Check participants.tsv
    90→        self.check_participants_file(project, &mut issues)?;
    91→
    92→        // Check dataset_description.json
    93→        self.check_dataset_description(project, &mut issues)?;
    94→
    95→        // Check subject directories
    96→        self.check_subject_directories(project, &mut issues, &mut files_checked)?;
    97→
    98→        // Check if there are any critical issues
    99→        let passed = !issues.iter().any(|issue| issue.severity == Severity::Critical);
   100→
   101→        Ok(ComplianceResult {
   102→            passed,
   103→            issues,
   104→            files_checked,
   105→        })
   106→    }
   107→
   108→    /// Check for required files
   109→    fn check_required_files(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   110→        // Check participants.tsv
   111→        let participants_file = project.path.join("participants.tsv");
   112→        if !participants_file.exists() {
   113→            issues.push(ComplianceIssue {
   114→                severity: Severity::Critical,
   115→                description: "Missing required participants.tsv file".to_string(),
   116→                file: Some(participants_file),
   117→                rule: "participants.tsv".to_string(),
   118→            });
   119→        }
   120→
   121→        // Check dataset_description.json
   122→        let dataset_description = project.path.join("dataset_description.json");
   123→        if !dataset_description.exists() {
   124→            issues.push(ComplianceIssue {
   125→                severity: Severity::Critical,
   126→                description: "Missing required dataset_description.json file".to_string(),
   127→                file: Some(dataset_description),
   128→                rule: "dataset_description.json".to_string(),
   129→            });
   130→        }
   131→
   132→        Ok(())
   133→    }
   134→
   135→    /// Check participants.tsv file
   136→    fn check_participants_file(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   137→        let participants_file = project.path.join("participants.tsv");
   138→        if !participants_file.exists() {
   139→            return Ok(()); // Already checked in check_required_files
   140→        }
   141→
   142→        // Read and validate participants.tsv
   143→        let content = std::fs::read_to_string(&participants_file)?;
   144→        let lines: Vec<&str> = content.lines().collect();
   145→        
   146→        if lines.is_empty() {
   147→            issues.push(ComplianceIssue {
   148→                severity: Severity::Critical,
   149→                description: "participants.tsv is empty".to_string(),
   150→                file: Some(participants_file.clone()),
   151→                rule: "participants_empty".to_string(),
   152→            });
   153→            return Ok(());
   154→        }
   155→
   156→        // Check header
   157→        let header = lines[0];
   158→        let columns: Vec<&str> = header.split('\t').collect();
   159→        
   160→        if columns.is_empty() || columns[0] != "participant_id" {
   161→            issues.push(ComplianceIssue {
   162→                severity: Severity::Critical,
   163→                description: "participants.tsv must have 'participant_id' as first column".to_string(),
   164→                file: Some(participants_file.clone()),
   165→                rule: "participants_header".to_string(),
   166→            });
   167→        }
   168→
   169→        // Validate participant IDs
   170→        for (i, line) in lines.iter().skip(1).enumerate() {
   171→            if line.is_empty() { continue; }
   172→            
   173→            let fields: Vec<&str> = line.split('\t').collect();
   174→            if fields.is_empty() { continue; }
   175→            
   176→            let participant_id = fields[0];
   177→            if !participant_id.starts_with("sub-") {
   178→                issues.push(ComplianceIssue {
   179→                    severity: Severity::Critical,
   180→                    description: format!("Invalid participant ID '{}' on line {}: must start with 'sub-'", 
   181→                                       participant_id, i + 2),
   182→                    file: Some(participants_file.clone()),
   183→                    rule: "participant_id_format".to_string(),
   184→                });
   185→            }
   186→            
   187→            // Check if participant directory exists
   188→            let participant_dir = project.path.join(participant_id);
   189→            if !participant_dir.exists() {
   190→                issues.push(ComplianceIssue {
   191→                    severity: Severity::High,
   192→                    description: format!("Participant '{}' listed in participants.tsv but directory not found", 
   193→                                       participant_id),
   194→                    file: Some(participants_file.clone()),
   195→                    rule: "participant_directory_missing".to_string(),
   196→                });
   197→            }
   198→        }
   199→
   200→        Ok(())
   201→    }
   202→
   203→    /// Check dataset_description.json file
   204→    fn check_dataset_description(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   205→        // Check required fields in dataset description
   206→        if let Some(name) = project.description.get("Name") {
   207→            if name.as_str().map_or(true, |s| s.is_empty()) {
   208→                issues.push(ComplianceIssue {
   209→                    severity: Severity::Critical,
   210→                    description: "Dataset name is missing or empty".to_string(),
   211→                    file: Some(project.path.join("dataset_description.json")),
   212→                    rule: "dataset_description.Name".to_string(),
   213→                });
   214→            }
   215→        } else {
   216→            issues.push(ComplianceIssue {
   217→                severity: Severity::Critical,
   218→                description: "Dataset name is missing from dataset_description.json".to_string(),
   219→                file: Some(project.path.join("dataset_description.json")),
   220→                rule: "dataset_description.Name".to_string(),
   221→            });
   222→        }
   223→
   224→        // Check BIDS version
   225→        if let Some(bids_version) = project.description.get("BIDSVersion") {
   226→            if bids_version.as_str().map_or(true, |s| s.is_empty()) {
   227→                issues.push(ComplianceIssue {
   228→                    severity: Severity::High,
   229→                    description: "BIDSVersion is missing or empty".to_string(),
   230→                    file: Some(project.path.join("dataset_description.json")),
   231→                    rule: "dataset_description.BIDSVersion".to_string(),
   232→                });
   233→            }
   234→        } else {
   235→            issues.push(ComplianceIssue {
   236→                severity: Severity::High,
   237→                description: "BIDSVersion is missing from dataset_description.json".to_string(),
   238→                file: Some(project.path.join("dataset_description.json")),
   239→                rule: "dataset_description.BIDSVersion".to_string(),
   240→            });
   241→        }
   242→
   243→        Ok(())
   244→    }
   245→
   246→    /// Check subject directories
   247→    fn check_subject_directories(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>, files_checked: &mut usize) -> Result<()> {
   248→        for participant in &project.participants {
   249→            let subject_dir = project.path.join(format!("sub-{}", participant.id));
   250→            
   251→            if !subject_dir.exists() {
   252→                issues.push(ComplianceIssue {
   253→                    severity: Severity::Critical,
   254→                    description: format!("Subject directory sub-{} does not exist", participant.id),
   255→                    file: Some(subject_dir),
   256→                    rule: "subject_directory".to_string(),
   257→                });
   258→                continue;
   259→            }
   260→
   261→            // Check subject directory structure
   262→            self.check_subject_directory(&subject_dir.as_path(), &participant.id, issues, files_checked)?;
   263→        }
   264→
   265→        Ok(())
   266→    }
   267→
   268→    /// Check a single subject directory
   269→    fn check_subject_directory(&self, subject_dir: &Path, subject_id: &str, issues: &mut Vec<ComplianceIssue>, files_checked: &mut usize) -> Result<()> {
   270→        // Check directory naming convention
   271→        if !subject_dir.file_name().unwrap().to_str().unwrap().starts_with("sub-") {
   272→            issues.push(ComplianceIssue {
   273→                severity: Severity::Critical,
   274→                description: "Subject directory must start with 'sub-'".to_string(),
   275→                file: Some(subject_dir.to_path_buf()),
   276→                rule: "subject_directory_naming".to_string(),
   277→            });
   278→        }
   279→
   280→        // Walk through subject directory
   281→        for entry in WalkDir::new(subject_dir).min_depth(1).max_depth(3) {
   282→            let entry = entry?;
   283→            let path = entry.path();
   284→            
   285→            if path.is_file() {
   286→                *files_checked += 1;
   287→                
   288→                // Check file naming
   289→                if let Some(file_name) = path.file_name().and_then(|f| f.to_str()) {
   290→                    self.check_file_naming(path, file_name, subject_id, issues)?;
   291→                    
   292→                    // Check JSON sidecars have corresponding data files
   293→                    if file_name.ends_with(".json") && !file_name.contains("dataset_description") {
   294→                        self.check_json_sidecar(path, issues)?;
   295→                    }
   296→                }
   297→            } else if path.is_dir() {
   298→                // Check session/modality directory naming
   299→                if let Some(dir_name) = path.file_name().and_then(|f| f.to_str()) {
   300→                    self.check_directory_naming(path, dir_name, issues)?;
   301→                }
   302→            }
   303→        }
   304→
   305→        Ok(())
   306→    }
   307→
   308→    /// Check file naming conventions
   309→    fn check_file_naming(&self, path: &Path, file_name: &str, subject_id: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   310→        // Skip hidden files and common metadata files
   311→        if file_name.starts_with('.') || file_name == "participants.tsv" || file_name == "dataset_description.json" {
   312→            return Ok(());
   313→        }
   314→
   315→        // Check if file follows BIDS naming convention
   316→        let valid_extensions = vec![".nii", ".nii.gz", ".json", ".tsv", ".tsv.gz", ".bval", ".bvec"];
   317→        let has_valid_extension = valid_extensions.iter().any(|ext| file_name.ends_with(ext));
   318→        
   319→        if !has_valid_extension {
   320→            issues.push(ComplianceIssue {
   321→                severity: Severity::Medium,
   322→                description: format!("File has non-standard extension: {}", file_name),
   323→                file: Some(path.to_path_buf()),
   324→                rule: "file_extension".to_string(),
   325→            });
   326→        }
   327→
   328→        // Check for valid BIDS entities
   329→        if file_name.contains('_') {
   330→            let parts: Vec<&str> = file_name.split('_').collect();
   331→            for part in &parts[..parts.len()-1] { // Skip the suffix
   332→                if part.contains('-') && !self.is_valid_entity(part) {
   333→                    issues.push(ComplianceIssue {
   334→                        severity: Severity::High,
   335→                        description: format!("Invalid BIDS entity: {}", part),
   336→                        file: Some(path.to_path_buf()),
   337→                        rule: "bids_entity".to_string(),
   338→                    });
   339→                }
   340→            }
   341→        }
   342→
   343→        Ok(())
   344→    }
   345→
   346→    /// Check if an entity is valid
   347→    fn is_valid_entity(&self, entity: &str) -> bool {
   348→        let valid_entities = vec![
   349→            "sub", "ses", "task", "acq", "ce", "rec", "dir", "run", "mod",
   350→            "echo", "flip", "inv", "mt", "part", "proc", "hemi", "space",
   351→            "split", "recording", "chunk", "seg", "label", "desc"
   352→        ];
   353→        
   354→        if let Some(key) = entity.split('-').next() {
   355→            valid_entities.contains(&key)
   356→        } else {
   357→            false
   358→        }
   359→    }
   360→
   361→    /// Check directory naming conventions
   362→    fn check_directory_naming(&self, path: &Path, dir_name: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   363→        // Check session directories
   364→        if dir_name.contains("ses") && !dir_name.starts_with("ses-") {
   365→            issues.push(ComplianceIssue {
   366→                severity: Severity::Critical,
   367→                description: "Session directory must start with 'ses-'".to_string(),
   368→                file: Some(path.to_path_buf()),
   369→                rule: "session_directory_naming".to_string(),
   370→            });
   371→        }
   372→
   373→        // Check modality directories
   374→        let valid_modalities = vec!["anat", "func", "dwi", "fmap", "perf", "meg", "eeg", "ieeg", "beh"];
   375→        if !valid_modalities.contains(&dir_name) && !dir_name.starts_with("ses-") && !dir_name.starts_with("sub-") {
   376→            if self.check_recommendations {
   377→                issues.push(ComplianceIssue {
   378→                    severity: Severity::Low,
   379→                    description: format!("Non-standard modality directory: {}", dir_name),
   380→                    file: Some(path.to_path_buf()),
   381→                    rule: "modality_directory".to_string(),
   382→                });
   383→            }
   384→        }
   385→
   386→        Ok(())
   387→    }
   388→
   389→    /// Check JSON sidecar files have corresponding data files
   390→    fn check_json_sidecar(&self, json_path: &Path, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
   391→        let json_name = json_path.file_stem().unwrap().to_str().unwrap();
   392→        let parent = json_path.parent().unwrap();
   393→        
   394→        // Check for corresponding .nii/.nii.gz file
   395→        let nii_path = parent.join(format!("{}.nii", json_name));
   396→        let nii_gz_path = parent.join(format!("{}.nii.gz", json_name));
   397→        
   398→        if !nii_path.exists() && !nii_gz_path.exists() {
   399→            // Check if it's a task events JSON
   400→            if !json_name.contains("events") {
   401→                issues.push(ComplianceIssue {
   402→                    severity: Severity::Medium,
   403→                    description: format!("JSON sidecar {} has no corresponding data file", json_path.display()),
   404→                    file: Some(json_path.to_path_buf()),
   405→                    rule: "orphaned_sidecar".to_string(),
   406→                });
   407→            }
   408→        }
   409→        
   410→        Ok(())
   411→    }
   412→}
   413→
   414→impl Default for ComplianceChecker {
   415→    fn default() -> Self {
   416→        Self::new()
   417→    }
   418→}
   419→
   420→/// Quick compliance check for a BIDS project
   421→pub fn check_compliance(project: &BidsProject) -> Result<ComplianceResult> {
   422→    let checker = ComplianceChecker::new();
   423→    checker.check_project(project)
   424→}
   425→
   426→impl ComplianceResult {
   427→    /// Get a summary of issues by severity
   428→    pub fn summary(&self) -> HashMap<Severity, usize> {
   429→        let mut summary = HashMap::new();
   430→        for issue in &self.issues {
   431→            *summary.entry(issue.severity.clone()).or_insert(0) += 1;
   432→        }
   433→        summary
   434→    }
   435→    
   436→    /// Get all critical issues
   437→    pub fn critical_issues(&self) -> Vec<&ComplianceIssue> {
   438→        self.issues.iter()
   439→            .filter(|issue| issue.severity == Severity::Critical)
   440→            .collect()
   441→    }
   442→    
   443→    /// Check if there are any issues of a given severity
   444→    pub fn has_issues_of_severity(&self, severity: &Severity) -> bool {
   445→        self.issues.iter().any(|issue| &issue.severity == severity)
   446→    }
   447→}
   448→
   449→impl std::fmt::Display for ComplianceResult {
   450→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   451→        writeln!(f, "BIDS Compliance Check Result")?;
   452→        writeln!(f, "Status: {}", if self.passed { "PASSED" } else { "FAILED" })?;
   453→        writeln!(f, "Files checked: {}", self.files_checked)?;
   454→        writeln!(f, "Total issues: {}", self.issues.len())?;
   455→        
   456→        if !self.issues.is_empty() {
   457→            writeln!(f, "\nIssues by severity:")?;
   458→            let summary = self.summary();
   459→            for (severity, count) in summary {
   460→                writeln!(f, "  {:?}: {}", severity, count)?;
   461→            }
   462→            
   463→            writeln!(f, "\nDetailed issues:")?;
   464→            for (i, issue) in self.issues.iter().enumerate() {
   465→                writeln!(f, "{}. [{:?}] {}", i + 1, issue.severity, issue.description)?;
   466→                if let Some(file) = &issue.file {
   467→                    writeln!(f, "   File: {}", file.display())?;
   468→                }
   469→                writeln!(f, "   Rule: {}", issue.rule)?;
   470→            }
   471→        }
   472→        
   473→        Ok(())
   474→    }
   475→}
   476→
