    18→    /// Entity value (e.g., "01", "test", "rest")
    19→    pub value: String,
    20→    /// Whether this entity is required by the BIDS specification
    21→    pub required: bool,
    22→}
    23→
    24→impl BidsEntity {
    25→    /// Create a new BIDS entity
