   172→    pub fn description(&self) -> Option<&str> {
   173→        self.get_entity("desc")
   174→    }
   175→
   176→    /// Get all entities as a vector of BidsEntity
   177→    pub fn entities_vec(&self) -> Vec<BidsEntity> {
   178→        self.entities
   179→            .iter()
   180→            .map(|(k, v)| BidsEntity::new(k.clone(), v.clone()))
   181→            .collect()
   182→    }
   183→
   184→    /// Check if this file matches the given entity filter
   185→    pub fn matches_entity(&self, key: &str, pattern: &str) -> bool {
   186→        if let Some(value) = self.get_entity(key) {
   187→            if pattern == ".*" {
   188→                return true;
   189→            }
   190→            // Simple pattern matching - in a full implementation, this would use regex
   191→            value.contains(pattern)
   192→        } else {
   193→            false
   194→        }
   195→    }
   196→
   197→    /// Check if this file matches all given entity filters
   198→    pub fn matches_entities(&self, filters: &HashMap<String, String>) -> bool {
   199→        filters
   200→            .iter()
   201→            .all(|(key, pattern)| self.matches_entity(key, pattern))
   202→    }
   203→
   204→    /// Reconstruct BIDS filename from entities
   205→    pub fn reconstruct_filename(&self) -> String {
   206→        let mut parts = Vec::new();
   207→
   208→        // Standard BIDS entity order
   209→        let ordered_keys = [
   210→            "sub", "ses", "task", "acq", "ce", "dir", "rec", "run", "echo", "space", "desc",
   211→        ];
   212→
   213→        // Add ordered entities
   214→        for key in &ordered_keys {
   215→            if let Some(value) = self.get_entity(key) {
   216→                parts.push(format!("{}-{}", key, value));
   217→            }
   218→        }
   219→
   220→        // Add remaining entities (sorted for consistency)
   221→        let mut remaining_keys: Vec<_> = self
   222→            .entities
   223→            .keys()
   224→            .filter(|k| !ordered_keys.contains(&k.as_str()))
   225→            .collect();
   226→        remaining_keys.sort();
   227→
   228→        for key in remaining_keys {
   229→            if let Some(value) = self.entities.get(key) {
   230→                parts.push(format!("{}-{}", key, value));
   231→            }
   232→        }
   233→
   234→        // Add suffix and extension
   235→        let base_name = parts.join("_");
   236→        if !self.suffix.is_empty() {
   237→            format!("{}_{}.{}", base_name, self.suffix, self.extension)
   238→        } else {
   239→            format!("{}.{}", base_name, self.extension)
   240→        }
   241→    }
   242→
   243→    /// Add metadata
   244→    pub fn add_metadata(&mut self, key: impl Into<String>, value: serde_json::Value) {
   245→        self.metadata.insert(key.into(), value);
   246→    }
   247→
   248→    /// Get metadata value
   249→    pub fn get_metadata(&self, key: &str) -> Option<&serde_json::Value> {
   250→        self.metadata.get(key)
   251→    }
   252→
   253→    /// Check if this is a functional MRI file
   254→    pub fn is_func(&self) -> bool {
   255→        self.kind.as_deref() == Some("func") || self.modality.as_deref() == Some("bold")
   256→    }
   257→
   258→    /// Check if this is an anatomical MRI file
   259→    pub fn is_anat(&self) -> bool {
   260→        self.kind.as_deref() == Some("anat")
   261→            || self.modality.as_deref().map_or(false, |m| {
   262→                matches!(m, "T1w" | "T2w" | "FLAIR" | "PDw" | "T1rho" | "T1map" | "T2map")
   263→            })
   264→    }
   265→
   266→    /// Check if this is a derivative file
   267→    pub fn is_derivative(&self) -> bool {
   268→        self.is_derivative
   269→    }
   270→
   271→    /// Check if this is an event file
   272→    pub fn is_events(&self) -> bool {
   273→        self.suffix == "events" && self.extension == "tsv"
   274→    }
   275→
   276→    /// Check if this is a sidecar JSON file
   277→    pub fn is_sidecar(&self) -> bool {
   278→        self.extension == "json"
   279→    }
   280→
   281→    /// Check if this is a confounds file
   282→    pub fn is_confounds(&self) -> bool {
   283→        self.suffix.contains("confounds") || self.get_entity("desc").map_or(false, |d| d.contains("confounds"))
   284→    }
   285→
   286→    /// Validate BIDS compliance
   287→    pub fn validate(&self) -> Result<()> {
   288→        // Check for required subject entity
   289→        if self.subject().is_none() {
   290→            return Err(BidsError::compliance_error(
   291→                "Missing required 'sub' entity",
   292→                Some(self.path.clone()),
   293→            ));
   294→        }
   295→
   296→        // Check filename format
   297→        if let Some(filename) = self.filename() {
   298→            if !filename.chars().all(|c| c.is_ascii_alphanumeric() || "-_.".contains(c)) {
   299→                return Err(BidsError::compliance_error(
   300→                    "Filename contains invalid characters",
   301→                    Some(self.path.clone()),
   302→                ));
   303→            }
   304→        }
   305→
   306→        Ok(())
   307→    }
   308→}
