   392→        file.extension = self.extension.unwrap_or_default();
   393→        file.kind = self.kind;
   394→        file.modality = self.modality;
   395→        file.is_derivative = self.is_derivative;
   396→        file.metadata = self.metadata;
   397→
   398→        Ok(file)
