//! BIDS file representation and metadata
//!
//! This module provides structures for representing BIDS files and their metadata,
//! including entity extraction and filename reconstruction.

use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::fmt;
use serde::{Deserialize, Serialize};

use crate::error::{BidsError, Result};

/// BIDS entity representation
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct BidsEntity {
    /// Entity key (e.g., "sub", "ses", "task")
    pub key: String,
    /// Entity value (e.g., "01", "test", "rest")
    pub value: String,
    /// Whether this entity is required by the BIDS specification
    pub required: bool,
}

impl BidsEntity {
    /// Create a new BIDS entity
    pub fn new(key: impl Into<String>, value: impl Into<String>) -> Self {
        Self {
            key: key.into(),
            value: value.into(),
            required: false,
        }
    }

    /// Create a new required BIDS entity
    pub fn required(key: impl Into<String>, value: impl Into<String>) -> Self {
        Self {
            key: key.into(),
            value: value.into(),
            required: true,
        }
    }

    /// Get the canonical entity name (maps "subid" to "sub", "session" to "ses", etc.)
    pub fn canonical_key(&self) -> &str {
        match self.key.as_str() {
            "subid" => "sub",
            "session" => "ses",
            key => key,
        }
    }

    /// Format as BIDS entity string (e.g., "sub-01", "task-rest")
    pub fn to_bids_string(&self) -> String {
        format!("{}-{}", self.canonical_key(), self.value)
    }
}

impl fmt::Display for BidsEntity {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.to_bids_string())
    }
}

/// BIDS file representation
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct BidsFile {
    /// Full path to the file
    pub path: PathBuf,
    /// BIDS entities extracted from the filename
    pub entities: HashMap<String, String>,
    /// File suffix (e.g., "bold", "events", "T1w")
    pub suffix: String,
    /// File extension (e.g., "nii.gz", "tsv", "json")
    pub extension: String,
    /// File type/kind (e.g., "func", "anat", "derivatives")
    pub kind: Option<String>,
    /// Modality (e.g., "bold", "T1w", "dwi")
    pub modality: Option<String>,
    /// Whether this is a derivative file
    pub is_derivative: bool,
    /// Additional metadata
    pub metadata: HashMap<String, serde_json::Value>,
}

impl BidsFile {
    /// Create a new BIDS file representation
    pub fn new(path: impl Into<PathBuf>) -> Self {
        let path = path.into();
        Self {
            path,
            entities: HashMap::new(),
            suffix: String::new(),
            extension: String::new(),
            kind: None,
            modality: None,
            is_derivative: false,
            metadata: HashMap::new(),
        }
    }

    /// Get the filename without directory path
    pub fn filename(&self) -> Option<&str> {
        self.path.file_name().and_then(|n| n.to_str())
    }

    /// Get the filename without extension
    pub fn stem(&self) -> Option<&str> {
        self.path.file_stem().and_then(|s| s.to_str())
    }

    /// Get entity value by key
    pub fn get_entity(&self, key: &str) -> Option<&str> {
        self.entities.get(key).map(|s| s.as_str())
    }

    /// Set entity value
    pub fn set_entity(&mut self, key: impl Into<String>, value: impl Into<String>) {
        self.entities.insert(key.into(), value.into());
    }

    /// Get subject ID (without "sub-" prefix)
    pub fn subject(&self) -> Option<&str> {
        self.get_entity("sub").or_else(|| self.get_entity("subid"))
    }

    /// Get session ID (without "ses-" prefix)
    pub fn session(&self) -> Option<&str> {
        self.get_entity("ses").or_else(|| self.get_entity("session"))
    }

    /// Get task name
    pub fn task(&self) -> Option<&str> {
        self.get_entity("task")
    }

    /// Get run number
    pub fn run(&self) -> Option<&str> {
        self.get_entity("run")
    }

    /// Get acquisition parameters
    pub fn acquisition(&self) -> Option<&str> {
        self.get_entity("acq")
    }

    /// Get contrast enhancement
    pub fn contrast(&self) -> Option<&str> {
        self.get_entity("ce")
    }

    /// Get direction
    pub fn direction(&self) -> Option<&str> {
        self.get_entity("dir")
    }

    /// Get reconstruction algorithm
    pub fn reconstruction(&self) -> Option<&str> {
        self.get_entity("rec")
    }

    /// Get echo number
    pub fn echo(&self) -> Option<&str> {
        self.get_entity("echo")
    }

    /// Get space
    pub fn space(&self) -> Option<&str> {
        self.get_entity("space")
    }

    /// Get description
    pub fn description(&self) -> Option<&str> {
        self.get_entity("desc")
    }

    /// Get all entities as a vector of BidsEntity
    pub fn entities_vec(&self) -> Vec<BidsEntity> {
        self.entities
            .iter()
            .map(|(k, v)| BidsEntity::new(k.clone(), v.clone()))
            .collect()
    }

    /// Check if this file matches the given entity filter
    pub fn matches_entity(&self, key: &str, pattern: &str) -> bool {
        if let Some(value) = self.get_entity(key) {
            if pattern == ".*" {
                return true;
            }
            // Simple pattern matching - in a full implementation, this would use regex
            value.contains(pattern)
        } else {
            false
        }
    }

    /// Check if this file matches all given entity filters
    pub fn matches_entities(&self, filters: &HashMap<String, String>) -> bool {
        filters
            .iter()
            .all(|(key, pattern)| self.matches_entity(key, pattern))
    }

    /// Reconstruct BIDS filename from entities
    pub fn reconstruct_filename(&self) -> String {
        let mut parts = Vec::new();

        // Standard BIDS entity order
        let ordered_keys = [
            "sub", "ses", "task", "acq", "ce", "dir", "rec", "run", "echo", "space", "desc",
        ];

        // Add ordered entities
        for key in &ordered_keys {
            if let Some(value) = self.get_entity(key) {
                parts.push(format!("{}-{}", key, value));
            }
        }

        // Add remaining entities (sorted for consistency)
        let mut remaining_keys: Vec<_> = self
            .entities
            .keys()
            .filter(|k| !ordered_keys.contains(&k.as_str()))
            .collect();
        remaining_keys.sort();

        for key in remaining_keys {
            if let Some(value) = self.entities.get(key) {
                parts.push(format!("{}-{}", key, value));
            }
        }

        // Add suffix and extension
        let base_name = parts.join("_");
        if !self.suffix.is_empty() {
            format!("{}_{}.{}", base_name, self.suffix, self.extension)
        } else {
            format!("{}.{}", base_name, self.extension)
        }
    }

    /// Add metadata
    pub fn add_metadata(&mut self, key: impl Into<String>, value: serde_json::Value) {
        self.metadata.insert(key.into(), value);
    }

    /// Get metadata value
    pub fn get_metadata(&self, key: &str) -> Option<&serde_json::Value> {
        self.metadata.get(key)
    }

    /// Check if this is a functional MRI file
    pub fn is_func(&self) -> bool {
        self.kind.as_deref() == Some("func") || self.modality.as_deref() == Some("bold")
    }

    /// Check if this is an anatomical MRI file
    pub fn is_anat(&self) -> bool {
        self.kind.as_deref() == Some("anat")
            || self.modality.as_deref().map_or(false, |m| {
                matches!(m, "T1w" | "T2w" | "FLAIR" | "PDw" | "T1rho" | "T1map" | "T2map")
            })
    }

    /// Check if this is a derivative file
    pub fn is_derivative(&self) -> bool {
        self.is_derivative
    }

    /// Check if this is an event file
    pub fn is_events(&self) -> bool {
        self.suffix == "events" && self.extension == "tsv"
    }

    /// Check if this is a sidecar JSON file
    pub fn is_sidecar(&self) -> bool {
        self.extension == "json"
    }

    /// Check if this is a confounds file
    pub fn is_confounds(&self) -> bool {
        self.suffix.contains("confounds") || self.get_entity("desc").map_or(false, |d| d.contains("confounds"))
    }

    /// Validate BIDS compliance
    pub fn validate(&self) -> Result<()> {
        // Check for required subject entity
        if self.subject().is_none() {
            return Err(BidsError::compliance_error(
                "Missing required 'sub' entity",
                Some(self.path.clone()),
            ));
        }

        // Check filename format
        if let Some(filename) = self.filename() {
            if !filename.chars().all(|c| c.is_ascii_alphanumeric() || "-_.".contains(c)) {
                return Err(BidsError::compliance_error(
                    "Filename contains invalid characters",
                    Some(self.path.clone()),
                ));
            }
        }

        Ok(())
    }
}

impl fmt::Display for BidsFile {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.path.display())
    }
}

/// Builder for constructing BIDS files
#[derive(Debug, Default)]
pub struct BidsFileBuilder {
    path: Option<PathBuf>,
    entities: HashMap<String, String>,
    suffix: Option<String>,
    extension: Option<String>,
    kind: Option<String>,
    modality: Option<String>,
    is_derivative: bool,
    metadata: HashMap<String, serde_json::Value>,
}

impl BidsFileBuilder {
    /// Create a new builder
    pub fn new() -> Self {
        Self::default()
    }

    /// Set the file path
    pub fn path(mut self, path: impl Into<PathBuf>) -> Self {
        self.path = Some(path.into());
        self
    }

    /// Add an entity
    pub fn entity(mut self, key: impl Into<String>, value: impl Into<String>) -> Self {
        self.entities.insert(key.into(), value.into());
        self
    }

    /// Set the suffix
    pub fn suffix(mut self, suffix: impl Into<String>) -> Self {
        self.suffix = Some(suffix.into());
        self
    }

    /// Set the extension
    pub fn extension(mut self, extension: impl Into<String>) -> Self {
        self.extension = Some(extension.into());
        self
    }

    /// Set the kind
    pub fn kind(mut self, kind: impl Into<String>) -> Self {
        self.kind = Some(kind.into());
        self
    }

    /// Set the modality
    pub fn modality(mut self, modality: impl Into<String>) -> Self {
        self.modality = Some(modality.into());
        self
    }

    /// Mark as derivative
    pub fn derivative(mut self, is_derivative: bool) -> Self {
        self.is_derivative = is_derivative;
        self
    }

    /// Add metadata
    pub fn metadata(mut self, key: impl Into<String>, value: serde_json::Value) -> Self {
        self.metadata.insert(key.into(), value);
        self
    }

    /// Build the BIDS file
    pub fn build(self) -> Result<BidsFile> {
        let path = self.path.ok_or_else(|| {
            BidsError::validation_error("Path is required", Some("path".to_string()))
        })?;

        let mut file = BidsFile::new(path);
        file.entities = self.entities;
        file.suffix = self.suffix.unwrap_or_default();
        file.extension = self.extension.unwrap_or_default();
        file.kind = self.kind;
        file.modality = self.modality;
        file.is_derivative = self.is_derivative;
        file.metadata = self.metadata;

        Ok(file)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_bids_entity_creation() {
        let entity = BidsEntity::new("sub", "01");
        assert_eq!(entity.key, "sub");
        assert_eq!(entity.value, "01");
        assert!(!entity.required);
        assert_eq!(entity.to_bids_string(), "sub-01");
    }

    #[test]
    fn test_bids_entity_canonical_key() {
        let entity = BidsEntity::new("subid", "01");
        assert_eq!(entity.canonical_key(), "sub");
        assert_eq!(entity.to_bids_string(), "sub-01");
    }

    #[test]
    fn test_bids_file_creation() {
        let file = BidsFile::new("/path/to/sub-01_task-rest_bold.nii.gz");
        assert_eq!(file.path.to_str(), Some("/path/to/sub-01_task-rest_bold.nii.gz"));
        assert_eq!(file.filename(), Some("sub-01_task-rest_bold.nii.gz"));
    }

    #[test]
    fn test_bids_file_entities() {
        let mut file = BidsFile::new("/path/to/test.nii.gz");
        file.set_entity("sub", "01");
        file.set_entity("task", "rest");
        file.set_entity("run", "01");

        assert_eq!(file.subject(), Some("01"));
        assert_eq!(file.task(), Some("rest"));
        assert_eq!(file.run(), Some("01"));
    }

    #[test]
    fn test_bids_file_matching() {
        let mut file = BidsFile::new("/path/to/test.nii.gz");
        file.set_entity("sub", "01");
        file.set_entity("task", "rest");

        assert!(file.matches_entity("sub", "01"));
        assert!(file.matches_entity("task", "rest"));
        assert!(!file.matches_entity("run", "01"));
        assert!(file.matches_entity("sub", ".*"));
    }

    #[test]
    fn test_bids_file_reconstruction() {
        let mut file = BidsFile::new("/path/to/test.nii.gz");
        file.set_entity("sub", "01");
        file.set_entity("task", "rest");
        file.set_entity("run", "01");
        file.suffix = "bold".to_string();
        file.extension = "nii.gz".to_string();

        let reconstructed = file.reconstruct_filename();
        assert_eq!(reconstructed, "sub-01_task-rest_run-01_bold.nii.gz");
    }

    #[test]
    fn test_bids_file_builder() {
        let file = BidsFileBuilder::new()
            .path("/path/to/test.nii.gz")
            .entity("sub", "01")
            .entity("task", "rest")
            .suffix("bold")
            .extension("nii.gz")
            .kind("func")
            .modality("bold")
            .build()
            .unwrap();

        assert_eq!(file.subject(), Some("01"));
        assert_eq!(file.task(), Some("rest"));
        assert_eq!(file.suffix, "bold");
        assert_eq!(file.extension, "nii.gz");
        assert_eq!(file.kind, Some("func".to_string()));
        assert_eq!(file.modality, Some("bold".to_string()));
    }

    #[test]
    fn test_file_type_detection() {
        let mut func_file = BidsFile::new("/path/to/test.nii.gz");
        func_file.modality = Some("bold".to_string());
        assert!(func_file.is_func());

        let mut anat_file = BidsFile::new("/path/to/test.nii.gz");
        anat_file.modality = Some("T1w".to_string());
        assert!(anat_file.is_anat());

        let mut event_file = BidsFile::new("/path/to/test.tsv");
        event_file.suffix = "events".to_string();
        event_file.extension = "tsv".to_string();
        assert!(event_file.is_events());
    }

    #[test]
    fn test_bids_file_validation() {
        let mut file = BidsFile::new("/path/to/test.nii.gz");

        // Should fail without subject
        assert!(file.validate().is_err());

        // Should pass with subject
        file.set_entity("sub", "01");
        assert!(file.validate().is_ok());
    }
}

