   138→    /// Create a new BIDS project with fMRIPrep derivatives
   139→    ///
   140→    /// # Arguments
   141→    ///
   142→    /// * `path` - Path to the BIDS dataset root directory
   143→    /// * `derivatives_path` - Optional path to derivatives directory
   144→    ///
   145→    /// # Returns
   146→    ///
   147→    /// A new `BidsProject` instance with derivatives support
   148→    pub fn with_derivatives<P: AsRef<Path>>(
   149→        path: P,
   150→        derivatives_path: Option<P>,
   151→    ) -> Result<Self> {
   152→        let mut project = Self::new(path)?;
