   240→    /// Get project summary statistics
   241→    pub fn summary(&self) -> ProjectSummary {
   242→        // Discover modalities and count files
   243→        let mut modalities = std::collections::HashSet::new();
   244→        let mut n_files = 0;
   245→        let mut total_size = 0u64;
   246→        
   247→        // Walk through the project directory to gather statistics
   248→        if let Ok(entries) = walkdir::WalkDir::new(&self.path)
   249→            .min_depth(1)
   250→            .into_iter()
   251→            .filter_map(|e| e.ok())
   252→            .collect::<Vec<_>>()
   253→        {
   254→            for entry in entries {
   255→                if entry.file_type().is_file() {
   256→                    n_files += 1;
   257→                    
   258→                    // Get file size
   259→                    if let Ok(metadata) = entry.metadata() {
   260→                        total_size += metadata.len();
   261→                    }
   262→                    
   263→                    // Extract modality from path
   264→                    let path = entry.path();
   265→                    if let Some(parent) = path.parent() {
   266→                        if let Some(dir_name) = parent.file_name().and_then(|n| n.to_str()) {
   267→                            let valid_modalities = vec!["anat", "func", "dwi", "fmap", "perf", "meg", "eeg", "ieeg", "beh"];
   268→                            if valid_modalities.contains(&dir_name) {
   269→                                modalities.insert(dir_name.to_string());
   270→                            }
   271→                        }
   272→                    }
   273→                }
   274→            }
   275→        }
   276→        
   277→        ProjectSummary {
   278→            name: self.name.clone(),
   279→            n_participants: self.participants.len(),
   280→            n_sessions: if self.has_sessions {
   281→                Some(self.sessions().len())
   282→            } else {
   283→                None
   284→            },
   285→            n_tasks: self.tasks.len(),
   286→            has_derivatives: self.has_derivatives,
   287→            modalities: modalities.into_iter().collect(),
   288→            n_files,
   289→            total_size: if total_size > 0 { Some(total_size) } else { None },
   290→            tasks: self.tasks.clone(),
   291→        }
   292→    }
   293→
   294→    /// Validate that a directory contains a valid BIDS dataset
   295→    fn validate_bids_directory(path: &Path) -> Result<()> {
   296→        if !path.is_dir() {
   297→            return Err(BidsError::directory_not_found(path));
   298→        }
   299→
   300→        // Check for required files
   301→        let participants_file = path.join("participants.tsv");
   302→        if !participants_file.exists() {
   303→            return Err(BidsError::invalid_project(
   304→                path,
   305→                "Missing required participants.tsv file",
   306→            ));
   307→        }
   308→
   309→        let dataset_description = path.join("dataset_description.json");
   310→        if !dataset_description.exists() {
   311→            return Err(BidsError::invalid_project(
   312→                path,
   313→                "Missing required dataset_description.json file",
   314→            ));
   315→        }
   316→
   317→        Ok(())
   318→    }
   319→
   320→    /// Read dataset description from JSON file
   321→    fn read_dataset_description(path: &Path) -> Result<HashMap<String, serde_json::Value>> {
   322→        let desc_path = path.join("dataset_description.json");
   323→        let content = fs::read_to_string(&desc_path)?;
   324→        let description: HashMap<String, serde_json::Value> = serde_json::from_str(&content)?;
   325→        Ok(description)
   326→    }
   327→
   328→    /// Load participants from participants.tsv
   329→    fn load_participants(&mut self) -> Result<()> {
   330→        let participants_file = self.path.join("participants.tsv");
   331→        let mut reader = csv::ReaderBuilder::new()
   332→            .delimiter(b'\t')
   333→            .from_path(&participants_file)?;
   334→
   335→        let headers = reader.headers()?.clone();
   336→        
   337→        for result in reader.records() {
   338→            let record = result?;
   339→            
   340→            // Extract participant ID
   341→            let participant_id = record.get(0).ok_or_else(|| {
   342→                BidsError::parse_error("participants.tsv", "Missing participant_id column")
   343→            })?;
   344→            
   345→            // Remove "sub-" prefix if present
   346→            let participant_id = participant_id.trim_start_matches("sub-");
   347→            
   348→            let mut participant = Participant::new(participant_id);
   349→            
   350→            // Add metadata from other columns
   351→            for (i, header) in headers.iter().enumerate().skip(1) {
   352→                if let Some(value) = record.get(i) {
   353→                    participant.add_metadata(header, value);
   354→                }
   355→            }
   356→            
   357→            self.participants.push(participant);
   358→        }
   359→
   360→        Ok(())
   361→    }
