     1→//! fMRIPrep derivatives support
     2→//!
     3→//! This module provides functionality for working with fMRIPrep derivatives,
     4→//! including preprocessed functional scans and associated metadata.
     5→
     6→use std::path::PathBuf;
     7→use crate::error::{BidsError, Result};
     8→use crate::file::BidsFile;
     9→use crate::project::BidsProject;
    10→use crate::search::SearchBuilder;
    11→
    12→/// fMRIPrep derivatives handler
    13→pub struct DerivativesHandler<'a> {
    14→    /// Reference to the BIDS project
    15→    project: &'a BidsProject,
    16→    /// Path to the derivatives directory
    17→    derivatives_path: PathBuf,
    18→}
    19→
    20→impl<'a> DerivativesHandler<'a> {
    21→    /// Create a new derivatives handler
    22→    pub fn new(project: &'a BidsProject) -> Result<Self> {
    23→        let derivatives_path = project.derivatives_path.as_ref().ok_or_else(|| {
    24→            BidsError::unsupported_feature("No derivatives directory found")
    25→        })?;
    26→
    27→        Ok(Self {
    28→            project,
    29→            derivatives_path: derivatives_path.clone(),
    30→        })
    31→    }
    32→
    33→    /// Find preprocessed functional scans
    34→    pub fn preproc_scans(&self) -> SearchBuilder {
    35→        self.project
    36→            .search()
    37→            .derivatives(true)
    38→            .desc("preproc")
    39→            .suffix("bold")
    40→    }
    41→
    42→    /// Find confound files
    43→    pub fn confound_files(&self) -> SearchBuilder {
    44→        self.project
    45→            .search()
    46→            .derivatives(true)
    47→            .desc("confounds")
    48→            .suffix("regressors")
    49→    }
    50→
    51→    /// Find brain mask files
    52→    pub fn brain_masks(&self) -> SearchBuilder {
    53→        self.project
    54→            .search()
    55→            .derivatives(true)
    56→            .desc("brain")
    57→            .suffix("mask")
    58→    }
    59→
    60→    /// Check if derivatives are available
    61→    pub fn has_derivatives(&self) -> bool {
    62→        self.derivatives_path.exists()
    63→    }
    64→
    65→    /// Get derivatives path
    66→    pub fn derivatives_path(&self) -> &PathBuf {
    67→        &self.derivatives_path
    68→    }
    69→
    70→    /// Find all derivative files for a subject
    71→    pub fn subject_derivatives(&self, subject: &str) -> Result<Vec<BidsFile>> {
    72→        self.project
    73→            .search()
    74→            .derivatives(true)
    75→            .subject(subject)
    76→            .collect()
    77→    }
    78→
    79→    /// Find specific derivative types
    80→    pub fn find_derivatives_by_type(&self, derivative_type: &str) -> Result<Vec<BidsFile>> {
    81→        match derivative_type {
    82→            "preproc" => self.preproc_scans().collect(),
    83→            "confounds" => self.confound_files().collect(),
    84→            "masks" => self.brain_masks().collect(),
    85→            _ => Err(BidsError::unsupported_feature(
    86→                format!("Unknown derivative type: {}", derivative_type)
    87→            )),
    88→        }
    89→    }
    90→}
    91→
    92→/// fMRIPrep space definitions
    93→pub struct FmriprepSpaces;
    94→
    95→impl FmriprepSpaces {
    96→    /// Standard MNI space
    97→    pub const MNI152_NLIN2009C_ASYM: &'static str = "MNI152NLin2009cAsym";
    98→    
    99→    /// Standard MNI space (6th generation)
   100→    pub const MNI152_NLIN6_ASYM: &'static str = "MNI152NLin6Asym";
   101→    
   102→    /// Native space
   103→    pub const NATIVE: &'static str = "T1w";
   104→    
   105→    /// fsnative space
   106→    pub const FS_NATIVE: &'static str = "fsnative";
   107→    
   108→    /// Check if a space is a standard template
   109→    pub fn is_standard_space(space: &str) -> bool {
   110→        matches!(space, 
   111→            Self::MNI152_NLIN2009C_ASYM | 
   112→            Self::MNI152_NLIN6_ASYM
   113→        )
   114→    }
   115→    
   116→    /// Check if a space is native
   117→    pub fn is_native_space(space: &str) -> bool {
   118→        matches!(space, Self::NATIVE | Self::FS_NATIVE)
   119→    }
   120→    
   121→    /// Get all available standard spaces
   122→    pub fn standard_spaces() -> Vec<&'static str> {
   123→        vec![
   124→            Self::MNI152_NLIN2009C_ASYM,
   125→            Self::MNI152_NLIN6_ASYM,
   126→        ]
   127→    }
   128→}
   129→
   130→/// fMRIPrep derivative types
   131→pub struct FmriprepDerivatives;
